            {isLoggedIn && (
               <button 
                onClick={handleDashboardClick}
                className="group relative inline-flex items-center justify-center gap-3 px-8 py-3 md:py-4 border border-white text-white text-[10px] md:text-xs font-bold tracking-[0.2em] uppercase hover:bg-white hover:text-black transition-all duration-300 backdrop-blur-sm w-full sm:w-auto sm:min-w-[200px]"
              >
                Dashboard
              </button>
            )}
          </div>
        </div>
      </section>

      {/* Infinite Marquee with Parallax */}
      <div className="bg-luxury-gold text-white py-3 md:py-4 overflow-hidden whitespace-nowrap border-y border-white/10 relative z-30">
        {/* Parallax Wrapper */}
        <div style={{ transform: `translateX(${scrollY * -0.15}px)`, willChange: 'transform' }}>
          {/* Animation Wrapper: 30s duration, linear timing */}
          <div className="inline-flex animate-[marquee_30s_linear_infinite] hover:[animation-play-state:paused]">
            {[...Array(6)].map((_, i) => (
               <React.Fragment key={i}>
                  {marqueeItems.map((item, idx) => (
                     <React.Fragment key={idx}>
                        <span className={`text-[10px] md:text-xs mx-4 md:mx-8 ${idx % 2 === 0 ? 'font-bold uppercase tracking-[0.3em]' : 'font-serif italic'}`}>{item}</span>
                        <span className="mx-4 md:mx-8 text-black/50">•</span>
                     </React.Fragment>
                  ))}
               </React.Fragment>
            ))}
          </div>
        </div>
        <style>{`
          @keyframes marquee {
            0% { transform: translateX(0); }
            100% { transform: translateX(-50%); }
          }
        `}</style>
      </div>

      {/* Shop by Designer Section */}
      <section className="py-16 md:py-24 bg-luxury-cream border-b border-gray-100">
        <div className="max-w-7xl mx-auto px-6">
          <div className="text-center mb-12 md:mb-16">
            <span className="text-[10px] md:text-xs font-bold uppercase tracking-[0.3em] text-luxury-taupe mb-4 block">{designersSection.subtitle}</span>
            <h2 className="text-3xl md:text-5xl font-serif italic text-luxury-black">{designersSection.title}</h2>
          </div>

          <div className="flex flex-wrap justify-center gap-8 md:gap-20">
            {activeVendors.slice(0, 4).map((vendor) => (
              <div 
                key={vendor.id} 
                className="group flex flex-col items-center cursor-pointer w-[40%] md:w-auto"
                onClick={() => onDesignerClick(vendor.name)}
              >
                <div className="w-20 h-20 md:w-32 md:h-32 rounded-full border border-gray-100 p-1 mb-4 md:mb-6 transition-all duration-500 group-hover:border-luxury-gold group-hover:scale-105 shadow-sm group-hover:shadow-xl">
                  <div className="w-full h-full rounded-full overflow-hidden bg-gray-50 relative">
                    <img 
                      src={vendor.avatar} 
                      alt={vendor.name} 
                      className="w-full h-full object-cover grayscale group-hover:grayscale-0 transition-all duration-700 ease-out" 
                    />
                  </div>
                </div>
                <h3 className="text-xs md:text-sm font-bold uppercase tracking-widest border-b border-transparent group-hover:border-luxury-black pb-1 transition-all duration-300 text-luxury-charcoal text-center">
                  {vendor.name}
                </h3>
                <p className="text-[9px] md:text-[10px] text-luxury-taupe mt-1 md:mt-2 font-serif italic">{vendor.location}</p>
              </div>
            ))}
          </div>

          <div className="text-center mt-12 md:mt-16">
             <button 
                onClick={() => onNavigate('DESIGNERS')}
                className="text-[10px] md:text-xs font-bold uppercase tracking-widest border-b border-luxury-black pb-1 hover:text-luxury-gold hover:border-luxury-gold transition-colors text-luxury-black"
             >
                View All Ateliers
             </button>
          </div>
        </div>
      </section>

      {/* AI Curator Section */}
      <section className="py-16 md:py-24 bg-luxury-black text-luxury-cream overflow-hidden">
        <div className="max-w-7xl mx-auto px-6">
          <div className="flex items-center gap-3 mb-8 md:mb-12">
            <Sparkles className="text-luxury-gold" size={20} />
            <h3 className="text-[10px] md:text-xs font-bold tracking-widest uppercase">AI Trend Forecast</h3>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 md:gap-16 items-center">
            <div>
              {loadingTrend ? (
                <div className="h-48 flex items-center justify-center border border-white/10">
                  <Loader className="animate-spin text-luxury-gold" />
                </div>
              ) : trend ? (
                <div className="space-y-6 md:space-y-8 animate-fade-in">
                  <h2 className="text-3xl md:text-6xl font-serif leading-none">{trend.title}</h2>
                  <p className="text-gray-400 text-sm md:text-lg font-light leading-relaxed">
                    {trend.description}
                  </p>
                  <div className="space-y-2">
                    <p className="text-[10px] md:text-xs uppercase tracking-wider text-gray-500">Palette</p>
                    <div className="flex gap-4">
                      {trend.colorPalette.map((color, idx) => (
                        <div key={idx} className="w-8 h-8 md:w-12 md:h-12 rounded-full border border-white/10" style={{ backgroundColor: color }} />
                      ))}
                    </div>
                  </div>
                </div>
              ) : null}
            </div>

            <div className="relative hidden md:block">
               {/* Editorial Grid Mockup */}
               <div className="grid grid-cols-2 gap-4">
                  <img src="https://images.unsplash.com/photo-1584917865442-de89df76afd3?q=80&w=800" className="w-full h-64 object-cover grayscale hover:grayscale-0 transition-all duration-700" alt="African Fashion Trend 1" />
                  <img src="https://images.unsplash.com/photo-1589156280159-27698a70f29e?q=80&w=800" className="w-full h-64 object-cover mt-12 grayscale hover:grayscale-0 transition-all duration-700" alt="African Fashion Trend 2" />
               </div>
            </div>
          </div>
        </div>
      </section>

      {/* Campaign / Visual Section */}
      <section className="py-16 md:py-24 bg-luxury-cream">
        <div className="max-w-7xl mx-auto px-6">
           <div className="mb-12 text-center">
              <span className="text-[10px] md:text-xs font-bold uppercase tracking-[0.3em] text-luxury-taupe mb-2 block">{campaign.subtitle}</span>
              <h2 className="text-3xl md:text-4xl font-serif italic text-luxury-black">{campaign.title}</h2>
           </div>
           <div className="grid grid-cols-2 md:grid-cols-4 gap-2 md:gap-4 h-auto md:h-[600px] auto-rows-fr">
              <div 
                onClick={() => onNavigate('MARKETPLACE')}
                className="col-span-2 md:col-span-2 row-span-2 relative group overflow-hidden h-[300px] md:h-full cursor-pointer"
              >
                 <img src={campaign.image1} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105" alt="Outfit 1" />
                 <div className="absolute inset-0 bg-black/10 group-hover:bg-transparent transition-colors" />
                 <div className="absolute bottom-4 left-4 md:bottom-6 md:left-6 text-white opacity-100 md:opacity-0 group-hover:opacity-100 transition-opacity duration-500">
                    <p className="text-[10px] md:text-xs font-bold uppercase tracking-widest">{campaign.overlayText1}</p>
                 </div>
              </div>
              <div 
                onClick={() => onNavigate('MARKETPLACE')}
                className="col-span-1 relative group overflow-hidden h-[150px] md:h-full cursor-pointer"
              >
                 <img src={campaign.image2} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105" alt="Outfit 2" />
              </div>
              <div 
                onClick={() => onNavigate('MARKETPLACE')}
                className="col-span-1 relative group overflow-hidden h-[150px] md:h-full cursor-pointer"
              >
                 <img src={campaign.image3} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105" alt="Outfit 3" />
              </div>
               <div 
                 onClick={() => onNavigate('MARKETPLACE')}
                 className="col-span-2 relative group overflow-hidden h-[150px] md:h-full cursor-pointer"
               >
                 <img src={campaign.image4} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105" alt="Outfit 4" />
              </div>
           </div>
        </div>
      </section>

      {/* Spotlight Products */}
      <section className="py-16 md:py-24 max-w-7xl mx-auto px-6 bg-luxury-cream-dark">
        <div className="flex justify-between items-end mb-8 md:mb-12">
           <h2 className="text-2xl md:text-3xl font-serif italic text-luxury-black">{spotlightSection.title}</h2>
           <button onClick={() => onNavigate('MARKETPLACE')} className="text-[10px] md:text-xs uppercase border-b border-black pb-1 hover:text-luxury-gold hover:border-luxury-gold transition-colors text-luxury-black">View All</button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 md:gap-x-8 md:gap-y-12">
          {spotlightProducts.length > 0 ? spotlightProducts.map((product) => (
            <div key={product.id} className="group cursor-pointer" onClick={() => onNavigate('MARKETPLACE')}>
              <div className="relative overflow-hidden mb-4 md:mb-6 aspect-[3/4]">
                <img 
                  src={product.image} 
                  alt={product.name} 
                  className="w-full h-full object-cover transform group-hover:scale-110 transition-transform duration-700 ease-out"
                />
                {product.isNewSeason && (
                  <span className="absolute top-4 left-4 bg-white text-black text-[10px] font-bold px-2 py-1 uppercase tracking-wide">
                    New Season
                  </span>
                )}
              </div>
              <h3 className="font-bold text-xs md:text-sm uppercase tracking-wide mb-1 text-luxury-charcoal">{product.designer}</h3>
              <p className="font-serif text-base md:text-lg italic text-luxury-taupe mb-2">{product.name}</p>
              <p className="text-xs md:text-sm font-medium text-luxury-black">${product.price}</p>
            </div>
          )) : (
            <div className="col-span-3 text-center text-gray-400 py-12">
              <p>No products featured at the moment.</p>
            </div>
          )}
        </div>
      </section>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { ShoppingBag, X, Search, User, Globe, Trash2, ArrowRight, LogOut, Settings, CheckCircle, Ruler, Loader, Camera, Lock, ArrowLeft, Mail, Home, Store, Bell, Info, AlertTriangle, ChevronRight, Instagram, Twitter, Facebook } from 'lucide-react';
import { usePaystackPayment } from 'react-paystack';
import { NAV_LINKS } from '../constants.ts';
import { UserRole, ViewState, CartItem, Order, AppNotification } from '../types.ts';
import { auth } from '../services/firebase.ts';
import { markNotificationRead } from '../services/dataService.ts';

interface LayoutProps {
  children: React.ReactNode;
  role: UserRole;
  cart: CartItem[];
  isCartOpen: boolean;
  setIsCartOpen: (isOpen: boolean) => void;
  onUpdateCartItem: (index: number, updates: Partial<CartItem>) => void;
  onRemoveFromCart: (index: number) => void;
  onNavigate: (view: ViewState) => void;
  onRoleChange: (role: UserRole) => void;
  currentView: ViewState;
  isLoggedIn: boolean;
  onLogout: () => void;
  onPlaceOrder?: (order: Order) => Promise<void>;
  onVisualSearch?: (file: File) => Promise<void>;
  onAuthRequest?: (mode: 'LOGIN' | 'REGISTER', role: UserRole) => void;
  notifications?: AppNotification[];
  onRefreshNotifications?: () => void;
}

export const Layout: React.FC<LayoutProps> = ({ 
  children, 
  role, 
  cart,
  isCartOpen,
  setIsCartOpen,
  onUpdateCartItem,
  onRemoveFromCart,
  onNavigate,
  onRoleChange,
  currentView,
  isLoggedIn,
  onLogout,
  onPlaceOrder,
  onVisualSearch,
  onAuthRequest,
  notifications = [],
  onRefreshNotifications
}) => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [orderComplete, setOrderComplete] = useState(false);
  const [measurementError, setMeasurementError] = useState(false);
  const [isProcessingCheckout, setIsProcessingCheckout] = useState(false);
  const [isSearching, setIsSearching] = useState(false);

  // Notification State
  const [showNotifications, setShowNotifications] = useState(false);
  const [activeToast, setActiveToast] = useState<AppNotification | null>(null);
  const unreadCount = notifications.filter(n => !n.read).length;
  const notifDropdownRef = useRef<HTMLDivElement>(null);

  // Track the latest notification ID to detect new ones
  const latestNotificationIdRef = useRef<string | null>(null);
  const initializedRef = useRef(false);

  // Checkout State
  const [checkoutStep, setCheckoutStep] = useState<'CART' | 'PAYMENT'>('CART');
  const [customerEmail, setCustomerEmail] = useState('');

  // --- PAYSTACK CONFIGURATION ---
  const PAYSTACK_PUBLIC_KEY = 'pk_test_xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx'; 

  const cartTotal = cart.reduce((sum, item) => sum + item.price, 0);

  const paystackConfig = {
    reference: (new Date()).getTime().toString(),
    email: customerEmail,
    amount: cartTotal * 100, // Paystack expects amount in kobo (or lowest currency unit)
    publicKey: PAYSTACK_PUBLIC_KEY,
  };

  // Initialize Paystack hook
  // @ts-ignore - Types might not resolve perfectly in all envs without install
  const initializePayment = usePaystackPayment(paystackConfig);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Sync email when auth state changes or cart opens
  useEffect(() => {
      if (auth.currentUser?.email) {
          setCustomerEmail(auth.currentUser.email);
      }
  }, [auth.currentUser, isCartOpen]);

  // Reset checkout step when cart closes
  useEffect(() => {
    if (!isCartOpen) {
        setTimeout(() => setCheckoutStep('CART'), 500);
    }
  }, [isCartOpen]);

  // Click outside listener for notification dropdown
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notifDropdownRef.current && !notifDropdownRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  // --- NOTIFICATION TOAST LOGIC ---
  useEffect(() => {
      if (notifications.length > 0) {
          const newest = notifications[0];

          // Determine if we should show toast
          const isNew = newest.id !== latestNotificationIdRef.current;
          const isRelevant = !newest.read; // Only show unread as toasts
          const isRecent = (new Date().getTime() - new Date(newest.date).getTime()) < 60000; // Created in last minute

          // Handle first load vs updates
          if (isNew) {
              if (initializedRef.current && isRelevant && isRecent) {
                  setActiveToast(newest);
                  setTimeout(() => setActiveToast(null), 6000);
              }
              // Update ref
              latestNotificationIdRef.current = newest.id;
          }
          initializedRef.current = true;
      }
  }, [notifications]);

  const handleNotificationClick = async (notif: AppNotification) => {
      if (!notif.read) {
          await markNotificationRead(notif.id);
          if (onRefreshNotifications) onRefreshNotifications();
      }
      setActiveToast(null); // Dismiss toast if clicked
      if (notif.link) {
          onNavigate(notif.link as ViewState);
          setShowNotifications(false);
      }
  };

  const markAllRead = async () => {
      const unread = notifications.filter(n => !n.read);
      for (const n of unread) {
          await markNotificationRead(n.id);
      }
      if (onRefreshNotifications) onRefreshNotifications();
  };

  const handleDashboardClick = () => {
    if (role === UserRole.ADMIN) onNavigate('ADMIN_PANEL');
    else if (role === UserRole.VENDOR) onNavigate('VENDOR_DASHBOARD');
    else onNavigate('BUYER_DASHBOARD');
  };

  const handleCameraClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && onVisualSearch) {
      setIsSearching(true);
      try {
        await onVisualSearch(file);
      } finally {
        setIsSearching(false);
        if (fileInputRef.current) fileInputRef.current.value = '';
      }
    }
  };

  const handleProceedToPayment = () => {
    // Validate Pre-Orders
    const hasInvalidPreOrder = cart.some(item => 
      item.isPreOrder && (!item.measurements || item.measurements.length < 5)
    );

    if (hasInvalidPreOrder) {
      setMeasurementError(true);
      return;
    }
    setMeasurementError(false);

    if (!isLoggedIn) {
       onAuthRequest ? onAuthRequest('LOGIN', UserRole.BUYER) : onNavigate('AUTH');
       setIsCartOpen(false);
       return;
    }

    setCheckoutStep('PAYMENT');
  };

  // Called when Paystack success callback fires
  const onPaystackSuccess = async (reference: any) => {
    setIsProcessingCheckout(true);

    const newOrder: Order = {
        id: `ord_${Date.now()}`,
        customerName: customerEmail || 'Guest User', 
        date: new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }),
        total: cartTotal,
        status: 'Processing',
        items: [...cart]
    };

    try {
        if (onPlaceOrder) {
            await onPlaceOrder(newOrder);
        }
        setOrderComplete(true);
        setTimeout(() => {
          setOrderComplete(false);
          setIsCartOpen(false);
          handleDashboardClick();
        }, 2000);
    } catch (e) {
        console.error("Checkout failed", e);
        alert("Order creation failed. Please contact support.");
    } finally {
        setIsProcessingCheckout(false);
    }
  };

  const onPaystackClose = () => {
      console.log('Payment closed');
      setIsProcessingCheckout(false);
  };

  const handleFinalizeOrder = () => {
    if (!customerEmail) {
        alert("Please enter your email address for the receipt.");
        return;
    }
    setIsProcessingCheckout(true);
    // @ts-ignore
    initializePayment(onPaystackSuccess, onPaystackClose);
  };

  // Logic for Nav Appearance
  const isNavTransparent = currentView === 'LANDING' && !isScrolled;
  const navTextColor = isNavTransparent ? 'text-white' : 'text-luxury-black';

  return (
    <div className="min-h-screen bg-luxury-cream text-luxury-black font-sans selection:bg-luxury-gold selection:text-white transition-colors duration-500 relative">

      {/* Toast Notification */}
      {activeToast && (
        <div 
            onClick={() => handleNotificationClick(activeToast)}
            className="fixed top-24 right-6 z-[60] bg-white border border-luxury-gold/30 shadow-2xl p-4 max-w-sm w-full animate-slide-up flex gap-4 items-start rounded-sm cursor-pointer hover:bg-gray-50 transition-colors"
        >
            <div className="w-8 h-8 rounded-full bg-luxury-black text-luxury-gold flex items-center justify-center shrink-0">
                <Bell size={14} />
            </div>
            <div className="flex-1">
                <div className="flex justify-between items-start">
                    <h4 className="text-xs font-bold uppercase tracking-widest text-luxury-black mb-1">New Notification</h4>
                    <button onClick={(e) => { e.stopPropagation(); setActiveToast(null); }} className="text-gray-400 hover:text-black">
                        <X size={14} />
                    </button>
                </div>
                <p className="text-sm font-serif italic text-luxury-black mb-1">{activeToast.title}</p>
                <p className="text-xs text-gray-500 leading-relaxed">{activeToast.message}</p>
            </div>
        </div>
      )}

      {/* Navigation */}
      <nav 
        className={`fixed top-0 w-full z-50 transition-all duration-300 border-b border-transparent ${
          isScrolled ? 'bg-white/95 backdrop-blur-md border-gray-100 py-3' : 'bg-transparent py-6'
        }`}
      >
        <div className="max-w-7xl mx-auto px-6">
          <div className="flex justify-between items-center">

            {/* Logo */}
            <div 
              className={`text-2xl md:text-3xl font-serif font-bold tracking-widest cursor-pointer hover:opacity-70 transition-opacity ${navTextColor}`}
              onClick={() => onNavigate('LANDING')}
            >
              MyFitStore
            </div>

            {/* Desktop Nav */}
            <div className={`hidden md:flex gap-8 text-xs font-medium tracking-widest uppercase ${navTextColor}`}>
              {NAV_LINKS.map((link) => (
                <a 
                  key={link.label} 
                  onClick={() => onNavigate(link.view)}
                  className={`hover:text-luxury-gold transition-colors cursor-pointer ${currentView === link.view ? 'text-luxury-gold border-b border-luxury-gold pb-0.5' : ''}`}
                >
                  {link.label}
                </a>
              ))}
            </div>

            {/* Icons */}
            <div className={`flex items-center gap-4 md:gap-6 ${navTextColor}`}>
              {/* Visual Search */}
              <div className="relative group hidden md:block">
                  <button 
                      onClick={handleCameraClick}
                      className="hover:text-luxury-gold transition-colors relative"
                      title="Visual Search (Gemini)"
                  >
                      {isSearching ? <Loader size={20} className="animate-spin text-luxury-gold" /> : <Camera size={20} />}
                  </button>
                  <input 
                      type="file" 
                      ref={fileInputRef} 
                      onChange={handleFileChange} 
                      accept="image/*" 
                      className="hidden" 
                  />
              </div>

              <Search size={20} className="cursor-pointer hover:text-luxury-gold transition-colors hidden sm:block" />

              {/* Notification Bell */}
              <div className="relative" ref={notifDropdownRef}>
                  <button 
                      onClick={() => setShowNotifications(!showNotifications)}
                      className="relative hover:text-luxury-gold transition-colors"
                  >
                      <Bell size={20} />
                      {unreadCount > 0 && (
                          <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[8px] font-bold w-3 h-3 rounded-full flex items-center justify-center animate-pulse">
                              {unreadCount}
                          </span>
                      )}
                  </button>

                  {/* Dropdown */}
                  {showNotifications && (
                      <div className="absolute right-0 top-full mt-4 w-80 bg-white border border-gray-100 shadow-xl rounded-sm z-50 animate-slide-up text-luxury-black">
                          <div className="p-4 border-b border-gray-50 flex justify-between items-center">
                              <h4 className="text-xs font-bold uppercase tracking-widest">Notifications</h4>
                              {unreadCount > 0 && (
                                  <button onClick={markAllRead} className="text-[10px] text-luxury-gold hover:underline">Mark all read</button>
                              )}
                          </div>
                          <div className="max-h-80 overflow-y-auto">
                              {notifications.length === 0 ? (
                                  <div className="p-8 text-center text-gray-400">
                                      <p className="text-xs">No updates yet.</p>
                                  </div>
                              ) : (
                                  notifications.map(notif => (
                                      <div 
                                          key={notif.id} 
                                          onClick={() => handleNotificationClick(notif)}
                                          className={`p-4 border-b border-gray-50 hover:bg-gray-50 cursor-pointer transition-colors ${!notif.read ? 'bg-luxury-cream/30' : ''}`}
                                      >
                                          <div className="flex items-start gap-3">
                                              <div className={`mt-1 w-2 h-2 rounded-full shrink-0 ${!notif.read ? 'bg-luxury-gold' : 'bg-gray-200'}`} />
                                              <div>
                                                  <p className={`text-xs mb-1 ${!notif.read ? 'font-bold' : 'font-medium'}`}>{notif.title}</p>
                                                  <p className="text-[10px] text-gray-500 leading-relaxed line-clamp-2">{notif.message}</p>
                                                  <span className="text-[9px] text-gray-400 mt-2 block uppercase tracking-widest">
                                                      {new Date(notif.date).toLocaleDateString()}
                                                  </span>
                                              </div>
                                          </div>
                                      </div>
                                  ))
                              )}
                          </div>
                      </div>
                  )}
              </div>

              {/* User / Auth Menu (Desktop) */}
              <div className="relative group hidden md:block">
                {isLoggedIn ? (
                  <>
                    <User 
                      size={20} 
                      className="cursor-pointer transition-colors hover:text-luxury-gold"
                      onClick={() => onNavigate('PROFILE_SETTINGS')}
                    />

                    <div className="absolute right-0 top-full mt-2 w-56 bg-white border border-gray-100 shadow-xl opacity-0 group-hover:opacity-100 invisible group-hover:visible transition-all duration-200 text-luxury-black">
                      <div className="p-4 border-b border-gray-50">
                        <p className="text-xs text-gray-400 uppercase tracking-wider mb-1">Signed in as</p>
                        <p className="font-bold text-sm">{role}</p>
                      </div>

                      <button
                        onClick={handleDashboardClick}
                        className="w-full text-left px-4 py-3 text-sm hover:bg-gray-50 flex items-center gap-2"
                      >
                        <Settings size={14} /> Dashboard
                      </button>

                      <button
                        onClick={() => onNavigate('PROFILE_SETTINGS')}
                        className="w-full text-left px-4 py-3 text-sm hover:bg-gray-50 flex items-center gap-2"
                      >
                        <User size={14} /> Profile Settings
                      </button>

                      <button
                        onClick={onLogout}
                        className="w-full text-left px-4 py-3 text-sm hover:bg-gray-50 flex items-center gap-2 text-red-500"
                      >
                        <LogOut size={14} /> Sign Out
                      </button>
                    </div>
                  </>
                ) : (
                  <button 
                    onClick={() => onAuthRequest ? onAuthRequest('LOGIN', UserRole.BUYER) : onNavigate('AUTH')}
                    className="bg-black text-white px-5 py-2 text-[10px] font-bold uppercase tracking-widest hover:bg-luxury-gold transition-colors whitespace-nowrap"
                  >
                    Get Started
                  </button>
                )}
              </div>

              <div 
                className="relative cursor-pointer hover:text-luxury-gold transition-colors hidden md:block" 
                onClick={() => setIsCartOpen(true)}
              >
                <ShoppingBag size={20} />
                {cart.length > 0 && (
                  <span className="absolute -top-2 -right-2 bg-luxury-black text-white text-[10px] w-4 h-4 flex items-center justify-center rounded-full">
                    {cart.length}
                  </span>
                )}
              </div>
            </div>
          </div>

          {/* Mobile Quick Links (Visible Horizontal Scroll) */}
          <div className={`md:hidden flex gap-6 overflow-x-auto pb-2 mt-4 scrollbar-hide ${navTextColor} transition-colors duration-300`}>
            {NAV_LINKS.map(link => (
              <button 
                key={link.label}
                onClick={() => onNavigate(link.view)}
                className="text-[10px] font-bold uppercase tracking-widest whitespace-nowrap opacity-90 hover:opacity-100 shrink-0"
              >
                {link.label}
              </button>
            ))}
          </div>
        </div>
      </nav>

      {/* Cart Drawer */}
      <div 
        className={`fixed inset-0 z-[60] transition-visibility duration-500 ${isCartOpen ? 'visible' : 'invisible'}`}
      >
        <div 
          className={`absolute inset-0 bg-black/40 backdrop-blur-sm transition-opacity duration-500 ${isCartOpen ? 'opacity-100' : 'opacity-0'}`}
          onClick={() => setIsCartOpen(false)}
        />
        <div 
          className={`absolute right-0 top-0 h-full w-full max-w-md bg-white shadow-2xl transform transition-transform duration-500 ease-out flex flex-col ${isCartOpen ? 'translate-x-0' : 'translate-x-full'}`}
        >
          {/* Drawer Header */}
          <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-white z-10 text-black">
             <div className="flex items-center gap-3">
                 {checkoutStep === 'PAYMENT' && !orderComplete && (
                     <button onClick={() => setCheckoutStep('CART')} className="hover:text-luxury-gold transition-colors">
                         <ArrowLeft size={20} />
                     </button>
                 )}
                 <h2 className="text-xl font-serif italic">{checkoutStep === 'PAYMENT' ? 'Secure Payment' : 'Your Selection'}</h2>
             </div>
             <button onClick={() => setIsCartOpen(false)} className="hover:rotate-90 transition-transform duration-300">
               <X size={24} />
             </button>
          </div>

          <div className="flex-1 overflow-y-auto p-6 space-y-8 text-black">
            {orderComplete ? (
              <div className="h-full flex flex-col items-center justify-center text-center animate-fade-in">
                <CheckCircle size={64} className="text-green-500 mb-6" />
                <h3 className="text-2xl font-serif italic mb-2">Order Confirmed</h3>
                <p className="text-gray-500 text-sm max-w-xs">Your pieces are being prepared by the atelier. You will receive a confirmation shortly.</p>
              </div>
            ) : cart.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-gray-400">
                <ShoppingBag size={48} className="mb-4 opacity-20" />
                <p className="text-sm uppercase tracking-widest">Your bag is empty</p>
                <button 
                  onClick={() => { setIsCartOpen(false); onNavigate('MARKETPLACE'); }}
                  className="mt-6 text-xs underline hover:text-black"
                >
                  Start Shopping
                </button>
              </div>
            ) : checkoutStep === 'CART' ? (
              // CART VIEW
              cart.map((item, index) => (
                <div key={`${item.id}-${index}`} className="animate-fade-in">
                  <div className="flex gap-4 mb-4">
                    <div className="w-24 h-32 bg-gray-100 shrink-0">
                      <img src={item.image} alt={item.name} className="w-full h-full object-cover" />
                    </div>
                    <div className="flex-1 flex flex-col justify-between py-1">
                      <div>
                        <h3 className="text-xs font-bold uppercase tracking-widest mb-1">{item.designer}</h3>
                        <p className="font-serif italic text-sm text-gray-600 leading-tight">{item.name}</p>
                        <p className="text-xs text-gray-400 mt-2">Size: {item.size}</p>
                      </div>
                      <div className="flex justify-between items-end">
                        <span className="text-sm font-medium">${item.price}</span>
                        <button 
                          onClick={() => onRemoveFromCart(index)}
                          className="text-gray-400 hover:text-red-600 transition-colors"
                        >
                          <Trash2 size={16} />
                        </button>
                      </div>
                    </div>
                  </div>

                  {/* Pre-Order Custom Fit Section */}
                  {item.isPreOrder && (
                    <div className={`p-4 bg-gray-50 border ${measurementError && (!item.measurements || item.measurements.length < 5) ? 'border-red-300 bg-red-50' : 'border-gray-100'} rounded-sm`}>
                      <div className="flex items-center gap-2 mb-2 text-luxury-gold">
                        <Ruler size={14} />
                        <span className="text-[10px] font-bold uppercase tracking-widest">Pre-Order: Custom Fit</span>
                      </div>
                      <p className="text-xs text-gray-500 mb-2">This piece is made-to-order. Please provide your measurements (Bust, Waist, Hips, Height).</p>
