                                 </div>
                                 <div className="flex gap-2">
                                     <button onClick={() => handleVerify(v, 'REJECTED')} className="px-4 py-2 border border-red-200 text-red-600 text-xs font-bold uppercase hover:bg-red-50">Reject</button>
