     const result = [];
     for(let i = 6; i >= 0; i--) {
        const d = new Date(today);
        d.setDate(today.getDate() - i);
        const dayName = days[d.getDay()];
        result.push({ name: dayName, sales: 0, fullDate: d.toDateString() });
     }
     orders.forEach(order => {
        const orderDate = new Date(order.date);
