        if (isVendor && currentVendor) {
            const vendorItems = order.items.filter(i => i.designer === currentVendor.name);
            if (vendorItems.length === 0) return;
            orderTotal = vendorItems.reduce((sum, i) => sum + (i.price * (i.quantity || 1)), 0);
