                  <form onSubmit={(e) => { e.preventDefault(); handleSaveBuyerProfile(); }} className="space-y-6 bg-white p-8 border border-gray-100">
                      <div>
                          <label className="block text-[10px] font-bold uppercase mb-2">Full Name</label>
                          <input value={buyerForm.name} onChange={e => setBuyerForm({...buyerForm, name: e.target.value})} className="w-full border-b border-gray-200 py-2 focus:border-black outline-none" />
                      </div>
                      <div>
                          <label className="block text-[10px] font-bold uppercase mb-2">Measurements (cm)</label>
                          <div className="grid grid-cols-3 gap-4">
                              <input placeholder="Bust" value={buyerForm.bust} onChange={e => setBuyerForm({...buyerForm, bust: e.target.value})} className="border border-gray-200 p-2 text-sm" />
                              <input placeholder="Waist" value={buyerForm.waist} onChange={e => setBuyerForm({...buyerForm, waist: e.target.value})} className="border border-gray-200 p-2 text-sm" />
                              <input placeholder="Hips" value={buyerForm.hips} onChange={e => setBuyerForm({...buyerForm, hips: e.target.value})} className="border border-gray-200 p-2 text-sm" />
                          </div>
                      </div>
                      <button type="submit" disabled={isSubmitting} className="bg-black text-white px-6 py-3 text-xs font-bold uppercase">Save Profile</button>
                  </form>
              ) : (
                  <div className="bg-white p-8 border border-gray-100 text-center text-gray-500">
                      <p>Vendor settings are managed in the Store Design tab.</p>
                      <button onClick={() => setActiveTab('STORE_DESIGN')} className="mt-4 text-black underline text-xs font-bold uppercase">Go to Store Design</button>
                  </div>
              )}
           </div>
        )}

        {/* CMS Tab (Admin) */}
        {activeTab === 'CMS' && isAdmin && (
            <div className="max-w-4xl animate-fade-in">
                <h2 className="text-2xl font-serif italic mb-6">Site Content Management</h2>
                <div className="bg-white p-8 border border-gray-100 space-y-6">
                    <p className="text-sm text-gray-500">Edit the landing page text and imagery directly.</p>
                    <textarea 
                        className="w-full h-96 p-4 border border-gray-200 font-mono text-xs"
                        value={JSON.stringify(cmsForm, null, 2)}
                        onChange={(e) => {
                            try {
                                setCmsForm(JSON.parse(e.target.value));
                            } catch (err) {
                                // invalid json
                            }
                        }}
                    />
                    <button onClick={handleSaveCMS} className="bg-black text-white px-6 py-3 text-xs font-bold uppercase">Publish Updates</button>
                </div>
            </div>
        )}
      </main>
    </div>
  );
};

