                <button 
                  onClick={() => { setIsCartOpen(false); onNavigate('MARKETPLACE'); }}
                  className="mt-6 text-xs underline hover:text-black"
                >
                  Start Shopping
                </button>
              </div>
            ) : checkoutStep === 'CART' ? (
              // CART VIEW
              cart.map((item, index) => (
                <div key={`${item.id}-${index}`} className="animate-fade-in">
                  <div className="flex gap-4 mb-4">
                    <div className="w-24 h-32 bg-gray-100 shrink-0">
                      <img src={item.image} alt={item.name} className="w-full h-full object-cover" />
                    </div>
                    <div className="flex-1 flex flex-col justify-between py-1">
                      <div>
                        <h3 className="text-xs font-bold uppercase tracking-widest mb-1">{item.designer}</h3>
                        <p className="font-serif italic text-sm text-gray-600 leading-tight">{item.name}</p>
                        <p className="text-xs text-gray-400 mt-2">Size: {item.size}</p>
                      </div>
                      <div className="flex justify-between items-end">
                        <span className="text-sm font-medium">${item.price}</span>
                        <button 
                          onClick={() => onRemoveFromCart(index)}
                          className="text-gray-400 hover:text-red-600 transition-colors"
                        >
                          <Trash2 size={16} />
                        </button>
                      </div>
                    </div>
                  </div>

                  {/* Pre-Order Custom Fit Section */}
                  {item.isPreOrder && (
                    <div className={`p-4 bg-gray-50 border ${measurementError && (!item.measurements || item.measurements.length < 5) ? 'border-red-300 bg-red-50' : 'border-gray-100'} rounded-sm`}>
                      <div className="flex items-center gap-2 mb-2 text-luxury-gold">
                        <Ruler size={14} />
                        <span className="text-[10px] font-bold uppercase tracking-widest">Pre-Order: Custom Fit</span>
                      </div>
                      <p className="text-xs text-gray-500 mb-2">This piece is made-to-order. Please provide your measurements (Bust, Waist, Hips, Height).</p>
                      <textarea
                        value={item.measurements || ''}
                        onChange={(e) => onUpdateCartItem(index, { measurements: e.target.value })}
                        placeholder="e.g. Bust: 85cm, Waist: 64cm, Hips: 92cm, Height: 175cm"
                        className="w-full text-xs p-3 border border-gray-200 outline-none focus:border-black bg-white resize-none font-sans"
                        rows={3}
                      />
                      {measurementError && (!item.measurements || item.measurements.length < 5) && (
                        <p className="text-[10px] text-red-500 mt-1">* Measurements required for checkout</p>
                      )}
                    </div>
                  )}
                </div>
              ))
            ) : (
                // PAYMENT VIEW (Paystack)
                <div className="space-y-6 animate-fade-in">
                    <div className="bg-gray-50 p-4 rounded-sm border border-gray-100">
                        <div className="flex justify-between items-center mb-2">
                            <span className="text-xs font-bold uppercase text-gray-400">Total Amount</span>
                            <span className="font-bold text-lg">${cartTotal}</span>
                        </div>
                        <div className="flex gap-2 text-xs text-gray-400">
                           <Lock size={12} /> <span className="uppercase tracking-wider">Secured by Paystack</span>
                        </div>
                    </div>

                    <div className="space-y-4">
                        <div className="space-y-2">
                            <label className="text-[10px] font-bold uppercase tracking-widest text-gray-400">Email Address</label>
                            <div className="relative">
                                <input 
                                    type="email"
                                    placeholder="your@email.com"
                                    value={customerEmail}
                                    onChange={(e) => setCustomerEmail(e.target.value)}
                                    disabled={!!auth.currentUser?.email}
                                    className="w-full border-b border-gray-200 py-2 text-sm focus:border-black outline-none bg-transparent disabled:text-gray-500 disabled:bg-transparent"
                                />
                                <Mail size={16} className="absolute right-0 top-2 text-gray-400" />
                            </div>
                            <p className="text-[10px] text-gray-400">Receipt will be sent to this email.</p>
                        </div>
                    </div>

                    <div className="bg-blue-50 p-4 border border-blue-100 rounded-sm">
                        <p className="text-[10px] text-blue-800 leading-relaxed">
                            You will be redirected to Paystack to complete your secure payment. 
                            We accept Card, Bank Transfer, and USSD.
                        </p>
                    </div>
                </div>
            )}
          </div>

          {cart.length > 0 && !orderComplete && (
            <div className="p-6 bg-gray-50 border-t border-gray-100 text-black">
              {checkoutStep === 'CART' ? (
                <>
                  <div className="flex justify-between items-center mb-6 text-sm">
                    <span className="uppercase tracking-widest text-gray-500">Subtotal</span>
                    <span className="font-bold text-lg">${cartTotal}</span>
                  </div>
                  <button 
                    onClick={handleProceedToPayment}
                    className="w-full bg-luxury-black text-white py-4 text-xs font-bold uppercase tracking-[0.2em] hover:bg-luxury-gold transition-colors flex items-center justify-center gap-2 group"
                  >
                    Proceed to Checkout <ArrowRight size={16} className="group-hover:translate-x-1 transition-transform" />
                  </button>
                </>
              ) : (
                <button 
                  onClick={handleFinalizeOrder}
                  disabled={isProcessingCheckout}
                  className="w-full bg-luxury-black text-white py-4 text-xs font-bold uppercase tracking-[0.2em] hover:bg-luxury-gold transition-colors flex items-center justify-center gap-2 group disabled:opacity-70"
                >
                   {isProcessingCheckout ? (
                       <>Processing <Loader className="animate-spin" size={14} /></>
                   ) : (
                       <>Pay with Paystack <Lock size={16} /></>
                   )}
                </button>
              )}
            </div>
          )}
        </div>
      </div>

      <main className="pt-32 md:pt-20 pb-24 md:pb-0 min-h-screen">
        {children}
      </main>

      {/* Mobile Bottom Navigation */}
      {!['PRODUCT_DETAIL', 'AUTH'].includes(currentView) && (
        <div className="fixed bottom-0 left-0 w-full bg-white/95 backdrop-blur-xl border-t border-gray-100 z-50 md:hidden flex justify-around items-end px-2 pt-3 pb-safe shadow-[0_-4px_20px_rgba(0,0,0,0.02)]">
          <button onClick={() => onNavigate('LANDING')} className={`flex flex-col items-center gap-1 p-2 ${currentView === 'LANDING' ? 'text-black' : 'text-gray-400 hover:text-gray-600'}`}>
            <Home size={20} />
            <span className="text-[9px] font-bold uppercase tracking-widest">Home</span>
          </button>

          <button onClick={() => onNavigate('MARKETPLACE')} className={`flex flex-col items-center gap-1 p-2 ${currentView === 'MARKETPLACE' ? 'text-black' : 'text-gray-400 hover:text-gray-600'}`}>
            <Store size={20} />
            <span className="text-[9px] font-bold uppercase tracking-widest">Shop</span>
          </button>

          <div className="relative -top-6">
            <button 
              onClick={handleCameraClick}
              className="w-14 h-14 bg-black text-white rounded-full shadow-xl flex items-center justify-center hover:bg-luxury-gold transition-all transform hover:scale-105"
            >
              {isSearching ? <Loader size={20} className="animate-spin" /> : <Camera size={24} />}
            </button>
          </div>

          <button onClick={() => setIsCartOpen(true)} className={`flex flex-col items-center gap-1 p-2 ${isCartOpen ? 'text-black' : 'text-gray-400 hover:text-gray-600'}`}>
            <div className="relative">
              <ShoppingBag size={20} />
              {cart.length > 0 && (
                <span className="absolute -top-1 -right-1 bg-luxury-gold text-white text-[8px] w-3 h-3 flex items-center justify-center rounded-full border border-white">
                  {cart.length}
                </span>
              )}
            </div>
            <span className="text-[9px] font-bold uppercase tracking-widest">Bag</span>
          </button>

          <button 
            onClick={() => {
              if (!isLoggedIn) {
                onAuthRequest ? onAuthRequest('LOGIN', UserRole.BUYER) : onNavigate('AUTH');
              } else {
                handleDashboardClick();
              }
            }} 
            className={`flex flex-col items-center gap-1 p-2 ${['VENDOR_DASHBOARD', 'BUYER_DASHBOARD', 'ADMIN_PANEL', 'PROFILE_SETTINGS'].includes(currentView) ? 'text-black' : 'text-gray-400 hover:text-gray-600'}`}
          >
            <User size={20} />
            <span className="text-[9px] font-bold uppercase tracking-widest">{isLoggedIn ? 'Profile' : 'Login'}</span>
          </button>
        </div>
      )}

      <footer className="bg-luxury-black text-luxury-cream py-20 px-6 mt-20 hidden md:block">
        <div className="max-w-7xl mx-auto grid grid-cols-1 md:grid-cols-4 gap-12">
          <div>
            <h3 className="text-2xl font-serif font-bold tracking-widest mb-6">MyFitStore</h3>
            <p className="text-gray-400 text-sm leading-relaxed max-w-xs">
              Redefining luxury digital commerce through curation, technology, and sustainable innovation.
            </p>
          </div>
          <div>
            <h4 className="uppercase text-xs font-bold tracking-widest mb-6 text-white">Client Services</h4>
            <ul className="space-y-4 text-sm text-gray-400">
              <li>FAQ</li>
              <li>Shipping & Returns</li>
              <li>Size Guide</li>
              <li>Track Order</li>
            </ul>
          </div>
          <div>
            <h4 className="uppercase text-xs font-bold tracking-widest mb-6 text-white">The Company</h4>
            <ul className="space-y-4 text-sm text-gray-400">
              <li className="cursor-pointer hover:text-luxury-gold transition-colors" onClick={() => onNavigate('ABOUT')}>About Us</li>
              <li>Careers</li>
              <li className="cursor-pointer hover:text-luxury-gold transition-colors" onClick={() => onNavigate('PRICING')}>Membership & Pricing</li>
              <li>Sustainability</li>
            </ul>
          </div>
          <div>
            <h4 className="uppercase text-xs font-bold tracking-widest mb-6 text-white">Newsletter</h4>
            <div className="flex border-b border-gray-600 pb-2">
              <input type="email" placeholder="EMAIL ADDRESS" className="bg-transparent w-full outline-none text-white placeholder-gray-600 text-sm" />
              <button className="text-xs uppercase hover:text-luxury-gold">Join</button>
            </div>
          </div>
        </div>
        <div className="max-w-7xl mx-auto mt-20 pt-8 border-t border-gray-900 flex justify-between items-center text-xs text-gray-600">
          <div>© 2024 MyFitStore. ALL RIGHTS RESERVED.</div>
          <div className="flex gap-4">
             <Globe size={14} /> <span>US / USD</span>
          </div>
        </div>
      </footer>
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Filter, ChevronDown, Heart, Camera, X } from 'lucide-react';
import { Product, ViewState, Vendor } from '../types.ts';

interface MarketplaceViewProps {
  onProductSelect: (product: Product) => void;
  onNavigate: (view: ViewState) => void;
  initialDesigner?: string | null;
  products: Product[];
  vendors: Vendor[];
  customTitle?: string | null;
  onClearFilter?: () => void;
  savedItems?: Product[];
  onToggleSave?: (product: Product) => void;
}

const FILTERS = ['All', 'Outerwear', 'Bottoms', 'Knitwear', 'Footwear', 'Accessories'];

export const MarketplaceView: React.FC<MarketplaceViewProps> = ({ 
  onProductSelect, 
  initialDesigner, 
  products,
  vendors,
  customTitle,
  onClearFilter,
  savedItems = [],
  onToggleSave
}) => {
  const [activeCategory, setActiveCategory] = useState('All');
  const [activeDesigner, setActiveDesigner] = useState('All Designers');

  // Handle initial filter from props
  useEffect(() => {
    if (initialDesigner) {
      setActiveDesigner(initialDesigner);
    } else {
        setActiveDesigner('All Designers');
    }
  }, [initialDesigner]);

  // Extract unique active designers from passed products
  const designers = useMemo(() => {
    const unique = Array.from(new Set(products.map(p => p.designer)));
    return ['All Designers', ...unique.sort()];
  }, [products]);

  const filteredProducts = products.filter(p => {
    const matchesCategory = activeCategory === 'All' || p.category === activeCategory;
    const matchesDesigner = activeDesigner === 'All Designers' || p.designer === activeDesigner;
    return matchesCategory && matchesDesigner;
  });

  const isSaved = (productId: string) => savedItems.some(p => p.id === productId);

  return (
    <div className="min-h-screen pt-12 pb-24">
      {/* Header & Filters */}
      <div className="max-w-7xl mx-auto px-6 mb-8 md:mb-12 sticky top-20 z-30 bg-white/80 backdrop-blur-sm py-4 md:py-6 border-b border-gray-100/50 transition-all">
        <div className="flex flex-col gap-6 md:gap-8">

          {/* Top Row: Title + Designer Select */}
          <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4 md:gap-6">
            <div className="flex items-center gap-4">
                <h1 className="text-3xl md:text-4xl font-serif italic">
                    {customTitle || "Ready-to-Wear"}
                </h1>
                {customTitle && onClearFilter && (
                    <button 
                        onClick={onClearFilter}
                        className="bg-gray-100 hover:bg-gray-200 text-[10px] md:text-xs font-bold uppercase tracking-widest px-3 py-1.5 rounded-full flex items-center gap-1 transition-colors duration-200 active:scale-95"
                    >
                        <X size={12} /> Clear
                    </button>
                )}
            </div>

            {/* Designer Dropdown */}
            {!customTitle && (
            <div className="relative w-full md:w-auto md:min-w-[240px]">
              <label className="text-[10px] uppercase tracking-widest text-gray-400 mb-2 block font-bold">Filter by Designer</label>
              <div className="relative group">
                <select 
                  value={activeDesigner}
                  onChange={(e) => setActiveDesigner(e.target.value)}
                  className="w-full appearance-none bg-transparent border-b border-gray-300 py-2 pr-8 text-sm font-bold uppercase tracking-widest focus:outline-none focus:border-black cursor-pointer hover:border-luxury-gold transition-colors duration-200"
                >
                  {designers.map(d => (
                    <option key={d} value={d}>{d}</option>
                  ))}
                </select>
                <ChevronDown size={14} className="absolute right-0 top-1/2 -translate-y-1/2 pointer-events-none text-gray-400 group-hover:text-black transition-colors" />
              </div>
            </div>
            )}
          </div>

          {/* Bottom Row: Category Pills */}
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2 md:gap-3 overflow-x-auto w-full pb-2 scrollbar-hide -mx-6 px-6 md:mx-0 md:px-0">
              {FILTERS.map(cat => (
                <button
                  key={cat}
                  onClick={() => setActiveCategory(cat)}
                  className={`text-[10px] md:text-xs uppercase tracking-widest whitespace-nowrap px-4 md:px-6 py-2 border rounded-full transition-all duration-200 active:scale-95 ${
                    activeCategory === cat 
                      ? 'bg-black text-white border-black' 
                      : 'bg-transparent text-gray-500 border-gray-200 hover:border-black hover:text-black'
                  }`}
                >
                  {cat}
                </button>
              ))}
            </div>
             <button className="hidden md:flex items-center gap-2 text-xs uppercase font-bold ml-4 border-l pl-6 border-gray-200 hover:text-luxury-gold transition-colors duration-200 whitespace-nowrap active:scale-95">
              <Filter size={14} /> More Filters
            </button>
          </div>

        </div>
      </div>

      {/* Grid */}
      <div className="max-w-7xl mx-auto px-6">
        {filteredProducts.length === 0 ? (
           <div className="py-24 text-center animate-fade-in">
             <div className="flex justify-center mb-4">
                {customTitle ? <Camera size={32} className="text-gray-300" /> : <Filter size={32} className="text-gray-300" />}
             </div>
             <p className="text-xl font-serif italic text-gray-400 mb-4">
                 {customTitle ? "No visual matches found in our current collection." : "No pieces found matching your criteria."}
             </p>
             <button 
               onClick={() => {
                   if (onClearFilter) onClearFilter();
                   setActiveCategory('All'); 
                   setActiveDesigner('All Designers');
               }} 
               className="text-xs font-bold uppercase border-b border-black pb-1 hover:text-luxury-gold hover:border-luxury-gold transition-colors duration-200 active:scale-95"
             >
               View Full Collection
             </button>
           </div>
        ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-x-6 gap-y-12 md:gap-y-16 animate-fade-in">
          {filteredProducts.map((product) => (
            <div 
              key={product.id} 
              className="group cursor-pointer active:scale-[0.99] transition-transform duration-200"
              onClick={() => onProductSelect(product)}
            >
              <div className="relative aspect-[3/4] overflow-hidden bg-gray-100 mb-4 md:mb-6">
                <img 
                  src={product.image} 
                  alt={product.name} 
                  className="w-full h-full object-cover transition-transform duration-500 ease-out group-hover:scale-110"
                />

                {/* Overlay Action */}
                <div className="absolute inset-0 bg-black/10 transition-opacity duration-300 opacity-0 group-hover:opacity-100 flex items-end justify-center pb-8">
                  <button className="bg-white text-black text-xs font-bold uppercase tracking-widest px-8 py-3 hover:bg-luxury-black hover:text-white transition-all duration-200 shadow-xl transform translate-y-4 opacity-0 group-hover:translate-y-0 group-hover:opacity-100 active:scale-95">
                    Quick View
                  </button>
                </div>

                <button 
                    onClick={(e) => { e.stopPropagation(); onToggleSave && onToggleSave(product); }}
                    className={`absolute top-4 right-4 transition-transform hover:scale-110 duration-300 opacity-0 group-hover:opacity-100 ${isSaved(product.id) ? 'opacity-100 text-luxury-gold' : 'text-white mix-blend-difference'}`}
                >
                  <Heart size={20} strokeWidth={1.5} fill={isSaved(product.id) ? "currentColor" : "none"} />
                </button>
              </div>

              <div className="flex justify-between items-start">
                <div>
                  <h3 className="text-[10px] md:text-xs font-bold uppercase tracking-widest mb-1">{product.designer}</h3>
                  <p className="font-serif text-sm md:text-base text-gray-600 italic group-hover:text-black transition-colors duration-200">{product.name}</p>
                </div>
                <span className="text-xs md:text-sm font-medium">${product.price}</span>
              </div>
            </div>
          ))}
        </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Star, Truck, ShieldCheck, Sparkles, User, Send, AlertCircle, Clock, Ruler, Heart } from 'lucide-react';
import { Product, Vendor } from '../types.ts';
import { getStyleMatch } from '../services/geminiService.ts';

interface ProductDetailProps {
  product: Product;
  vendor?: Vendor;
  onAddToCart: (product: Product, size: string, measurements?: string) => void;
  onBack: () => void;
  onViewDesigner?: () => void;
  featureFlags: { enableAiStyleMatch: boolean; enableReviews: boolean; };
  savedItems?: Product[];
  onToggleSave?: (product: Product) => void;
}

interface Review {
  id: string;
  author: string;
  rating: number;
  text: string;
  date: string;
}

export const ProductDetail: React.FC<ProductDetailProps> = ({ product, vendor, onAddToCart, onBack, onViewDesigner, featureFlags, savedItems = [], onToggleSave }) => {
  const [selectedSize, setSelectedSize] = useState<string | null>(null);
  const [sizeError, setSizeError] = useState(false);
  const [measurements, setMeasurements] = useState('');
  const [styleTip, setStyleTip] = useState<string | null>(null);
  const [loadingStyle, setLoadingStyle] = useState(false);
  const [activeImage, setActiveImage] = useState(product.image);

  // Reviews State
  const [reviews, setReviews] = useState<Review[]>([
    { id: 'r1', author: 'Elena K.', rating: 5, text: 'The fabric quality is unmatched. Fits perfectly.', date: '2 days ago' },
    { id: 'r2', author: 'Marc D.', rating: 4, text: 'Stunning silhouette, though the sleeves are slightly long.', date: '1 week ago' }
  ]);
  const [newReview, setNewReview] = useState('');
  const [newRating, setNewRating] = useState(5);

  const isSaved = savedItems.some(p => p.id === product.id);

  useEffect(() => {
    setActiveImage(product.image);
    setSelectedSize(null);
    setMeasurements('');
    setSizeError(false);
    setStyleTip(null);
  }, [product]);

  // Generate mock additional images for the gallery
  const galleryImages = [
    product.image,
    `https://picsum.photos/seed/${product.id}detail1/800/1200`,
    `https://picsum.photos/seed/${product.id}detail2/800/1200`,
    `https://picsum.photos/seed/${product.id}detail3/800/1200`,
  ];

  const handleStyleMatch = async () => {
    setLoadingStyle(true);
    const tip = await getStyleMatch(product.name);
    setStyleTip(tip);
    setLoadingStyle(false);
  };

  const handleAddToCartClick = () => {
    if (!selectedSize) {
      setSizeError(true);
      return;
    }
    setSizeError(false);
    onAddToCart(product, selectedSize, measurements);
  };

  const handleReviewSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newReview.trim()) return;
    const review: Review = {
      id: `new-${Date.now()}`,
      author: 'You', // In a real app, from auth context
      rating: newRating,
      text: newReview,
      date: 'Just now'
    };
    setReviews([review, ...reviews]);
    setNewReview('');
  };

  return (
    <div className="min-h-screen bg-white animate-fade-in pb-20 md:pb-0">
      <div className="max-w-7xl mx-auto px-6 py-12">
        <button onClick={onBack} className="text-xs uppercase font-bold tracking-widest mb-8 hover:text-luxury-gold transition-colors">
          ← Back to Marketplace
        </button>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-16 mb-24">
          {/* Gallery */}
          <div className="space-y-4">
            {/* Main Image */}
            <div className="aspect-[3/4] overflow-hidden bg-gray-50 cursor-zoom-in relative group">
              <img 
                src={activeImage} 
                alt={product.name} 
                className="w-full h-full object-cover hover:scale-110 transition-transform duration-700 ease-out" 
              />
              {product.isPreOrder && (
                 <div className="absolute top-4 left-4 bg-luxury-gold text-white px-3 py-1 text-[10px] font-bold uppercase tracking-widest flex items-center gap-1">
                   <Clock size={12} /> Pre-Order
                 </div>
              )}
              <button 
                onClick={() => onToggleSave && onToggleSave(product)}
                className={`absolute top-4 right-4 p-3 rounded-full bg-white/10 backdrop-blur-md border border-white/20 hover:bg-white hover:text-luxury-gold transition-all ${isSaved ? 'text-luxury-gold bg-white' : 'text-white'}`}
              >
                <Heart size={20} fill={isSaved ? "currentColor" : "none"} />
              </button>
            </div>
            {/* Thumbnails */}
            <div className="grid grid-cols-4 gap-4">
              {galleryImages.map((img, idx) => (
                <button 
                  key={idx}
                  onClick={() => setActiveImage(img)}
                  className={`aspect-[3/4] bg-gray-50 overflow-hidden transition-all duration-300 ${
                    activeImage === img 
                      ? 'ring-1 ring-black ring-offset-2 opacity-100' 
                      : 'opacity-60 hover:opacity-100'
                  }`}
                >
                  <img src={img} alt={`View ${idx + 1}`} className="w-full h-full object-cover" />
                </button>
              ))}
            </div>
          </div>

          {/* Info */}
          <div className="sticky top-32 h-fit space-y-8">
            <div>
              <div className="flex justify-between items-start mb-2">
                <h2 className="text-xl font-bold uppercase tracking-widest">{product.designer}</h2>
                <div className="flex items-center gap-1">
                  <Star size={14} className="fill-luxury-gold text-luxury-gold" />
                  <span className="text-xs font-medium">{product.rating} ({reviews.length} Reviews)</span>
                </div>
              </div>
              <h1 className="text-4xl font-serif italic mb-4">{product.name}</h1>
              <p className="text-2xl font-light">${product.price}</p>
            </div>

            <p className="text-gray-600 leading-relaxed font-light">
              {product.description} Constructed with precision and tailored for the modern silhouette. 
              This piece embodies the philosophy of {product.designer}, merging utility with high-fashion aesthetics.
            </p>

            {/* Designer Story Section */}
            {vendor && (
                <div className="border-l-2 border-luxury-gold pl-6 py-2 my-8 animate-fade-in">
                    <h4 className="text-xs font-bold uppercase tracking-widest text-gray-400 mb-2">Designer Story</h4>
                    <div className="flex items-center gap-4 mb-3">
                        <img src={vendor.avatar} alt={vendor.name} className="w-10 h-10 rounded-full object-cover" />
                        <span className="font-serif italic text-lg">{vendor.name}</span>
                    </div>
                    <p className="text-xs text-gray-500 leading-relaxed mb-3 line-clamp-3">{vendor.bio}</p>
                    <button 
                        onClick={onViewDesigner}
                        className="text-xs font-bold uppercase tracking-widest border-b border-black pb-0.5 hover:text-luxury-gold hover:border-luxury-gold transition-colors"
                    >
                        View Profile
                    </button>
                </div>
            )}

            {/* AI Style Match */}
            {featureFlags.enableAiStyleMatch && (
              <div className="p-6 bg-luxury-cream border border-luxury-gold/20 rounded-sm">
                <div className="flex items-center gap-2 mb-3">
                  <Sparkles size={16} className="text-luxury-gold" />
                  <h4 className="text-xs font-bold uppercase tracking-widest">MyFitStore AI Stylist</h4>
                </div>
                {styleTip ? (
                  <p className="text-sm font-serif italic text-gray-700 animate-fade-in">"{styleTip}"</p>
                ) : (
                  <button 
                    onClick={handleStyleMatch}
                    disabled={loadingStyle}
                    className="text-xs underline hover:text-luxury-gold disabled:opacity-50"
                  >
                    {loadingStyle ? 'Curating advice...' : 'Get Styling Advice'}
                  </button>
                )}
              </div>
            )}

            <div className="space-y-4">
              <div className="flex justify-between items-center">
                <p className={`text-xs font-bold uppercase ${sizeError ? 'text-red-500' : ''}`}>Select Size</p>
                {sizeError && <span className="text-xs text-red-500 flex items-center gap-1"><AlertCircle size={12}/> Required</span>}
              </div>

              <div className="flex flex-wrap gap-3">
                {product.sizes && product.sizes.length > 0 ? (
                  product.sizes.map(size => (
                  <button
                    key={size}
                    onClick={() => { setSelectedSize(size); setSizeError(false); }}
                    className={`min-w-[48px] h-12 px-3 flex items-center justify-center border text-sm transition-all ${
                      selectedSize === size 
                        ? 'bg-black text-white border-black' 
                        : 'border-gray-200 hover:border-black'
                    }`}
                  >
                    {size}
                  </button>
                ))) : (
                  <span className="text-sm text-gray-500 italic">One Size Only</span>
                )}
              </div>

              {/* Custom Measurements Section for Pre-Order */}
              {product.isPreOrder && (
                <div className="pt-4 animate-fade-in border-t border-gray-50 mt-4">
                  <div className="flex items-center gap-2 mb-3 text-luxury-gold">
                    <Ruler size={16} />
                    <span className="text-xs font-bold uppercase tracking-widest">Custom Measurements</span>
                  </div>
                  <p className="text-xs text-gray-500 mb-3 leading-relaxed">
                     For our made-to-order pieces, we ensure the perfect fit. Please provide your measurements (Bust, Waist, Hips, Height).
                  </p>
                  <textarea
                    value={measurements}
                    onChange={(e) => setMeasurements(e.target.value)}
                    placeholder="e.g. Bust: 85cm, Waist: 64cm, Hips: 92cm, Height: 175cm"
                    className="w-full p-4 border border-gray-200 bg-gray-50 text-sm focus:border-black outline-none min-h-[100px] resize-none font-serif placeholder-gray-400"
                  />
                </div>
              )}
            </div>

            <button 
              onClick={handleAddToCartClick}
              className="hidden md:block w-full bg-black text-white py-5 text-xs font-bold uppercase tracking-[0.2em] hover:bg-luxury-gold transition-colors"
            >
              {product.isPreOrder ? 'Pre-Order Now' : 'Add to Bag'}
            </button>

            {product.isPreOrder && (
              <p className="text-[10px] text-gray-500 text-center italic">
                * This item is made-to-measure. You will be asked for measurements at checkout.
              </p>
            )}

            <div className="grid grid-cols-2 gap-4 text-xs text-gray-500 pt-8 border-t border-gray-100">
              <div className="flex items-center gap-2">
                <Truck size={16} />
                <span>Free Express Shipping</span>
              </div>
              <div className="flex items-center gap-2">
                <ShieldCheck size={16} />
                <span>Authenticity Guaranteed</span>
              </div>
            </div>
          </div>
        </div>

        {/* Reviews Section */}
        {featureFlags.enableReviews && (
          <div className="border-t border-gray-100 pt-16">
            <h3 className="text-2xl font-serif italic mb-8">Client Reviews</h3>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-16">
              {/* Write Review */}
              <div className="bg-gray-50 p-8 h-fit">
                <h4 className="text-xs font-bold uppercase tracking-widest mb-6">Write a Review</h4>
                <form onSubmit={handleReviewSubmit} className="space-y-4">
                  <div className="flex gap-2 mb-4">
                    {[1, 2, 3, 4, 5].map((star) => (
                      <button
                        key={star}
                        type="button"
                        onClick={() => setNewRating(star)}
                        className={`transition-colors ${star <= newRating ? 'text-luxury-gold' : 'text-gray-300'}`}
                      >
                        <Star size={20} fill={star <= newRating ? 'currentColor' : 'none'} />
                      </button>
                    ))}
                  </div>
                  <textarea 
                    value={newReview}
                    onChange={(e) => setNewReview(e.target.value)}
                    placeholder="Share your thoughts on the fit, fabric, and style..."
                    className="w-full p-4 border border-gray-200 bg-white text-sm focus:border-black outline-none min-h-[120px]"
                  />
                  <button type="submit" className="flex items-center gap-2 text-xs font-bold uppercase tracking-widest bg-black text-white px-6 py-3 hover:bg-luxury-gold transition-colors">
                    <Send size={14} /> Submit Review
                  </button>
                </form>
              </div>

              {/* Review List */}
              <div className="space-y-8">
                {reviews.map((review) => (
                  <div key={review.id} className="border-b border-gray-100 pb-8 last:border-0 animate-fade-in">
                    <div className="flex justify-between items-start mb-2">
                      <div className="flex items-center gap-2">
                        <div className="w-8 h-8 bg-luxury-black text-white rounded-full flex items-center justify-center text-xs font-bold">
                          {review.author.charAt(0)}
                        </div>
                        <span className="text-sm font-bold">{review.author}</span>
                      </div>
                      <span className="text-xs text-gray-400">{review.date}</span>
                    </div>
                    <div className="flex gap-1 mb-3 text-luxury-gold">
                       {[...Array(5)].map((_, i) => (
                         <Star key={i} size={12} fill={i < review.rating ? 'currentColor' : 'none'} className={i < review.rating ? '' : 'text-gray-200'} />
                       ))}
                    </div>
                    <p className="text-gray-600 text-sm leading-relaxed font-serif italic">"{review.text}"</p>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Sticky Bottom Bar for Mobile */}
      <div className="fixed bottom-0 left-0 w-full bg-white border-t border-gray-100 p-4 md:hidden z-40 flex items-center gap-4 mb-[env(safe-area-inset-bottom)]">
         <div className="flex-1">
            <p className="text-xs font-bold uppercase line-clamp-1">{product.name}</p>
            <p className="text-sm">${product.price}</p>
         </div>
         <button 
            onClick={handleAddToCartClick}
            className="bg-black text-white px-8 py-3 text-xs font-bold uppercase tracking-widest shadow-lg hover:bg-luxury-gold transition-colors"
         >
            Add to Bag
         </button>
      </div>
    </div>
  );
};

