        {activeTab === 'PROFILE' && (
           <div className="max-w-2xl animate-fade-in">
              <h2 className="text-2xl font-serif italic mb-6 dark:text-white">Settings</h2>

              {isBuyer ? (
                  <form onSubmit={(e) => { e.preventDefault(); handleSaveBuyerProfile(); }} className="space-y-6 bg-white dark:bg-zinc-900 p-8 border border-gray-100 dark:border-zinc-800">
                      <div>
                          <label className="block text-[10px] font-bold uppercase mb-2 dark:text-gray-400">Full Name</label>
                          <input value={buyerForm.name} onChange={e => setBuyerForm({...buyerForm, name: e.target.value})} className="w-full border-b border-gray-200 dark:border-zinc-700 py-2 focus:border-black dark:focus:border-white outline-none bg-transparent dark:text-white" />
                      </div>
                      <div>
                          <label className="block text-[10px] font-bold uppercase mb-2 dark:text-gray-400">Measurements (cm)</label>
                          <div className="grid grid-cols-3 gap-4">
                              <input placeholder="Bust" value={buyerForm.bust} onChange={e => setBuyerForm({...buyerForm, bust: e.target.value})} className="border border-gray-200 dark:border-zinc-700 p-2 text-sm bg-transparent dark:text-white" />
                              <input placeholder="Waist" value={buyerForm.waist} onChange={e => setBuyerForm({...buyerForm, waist: e.target.value})} className="border border-gray-200 dark:border-zinc-700 p-2 text-sm bg-transparent dark:text-white" />
                              <input placeholder="Hips" value={buyerForm.hips} onChange={e => setBuyerForm({...buyerForm, hips: e.target.value})} className="border border-gray-200 dark:border-zinc-700 p-2 text-sm bg-transparent dark:text-white" />
                          </div>
                      </div>
                      <button type="submit" disabled={isSubmitting} className="bg-black text-white px-6 py-3 text-xs font-bold uppercase dark:bg-white dark:text-black">Save Profile</button>
                  </form>
              ) : (
                  <div className="bg-white dark:bg-zinc-900 p-8 border border-gray-100 dark:border-zinc-800 text-center text-gray-500">
                      <p>Vendor settings are managed in the Store Design tab.</p>
                      <button onClick={() => setActiveTab('STORE_DESIGN')} className="mt-4 text-black underline text-xs font-bold uppercase dark:text-white">Go to Store Design</button>
                  </div>
              )}
           </div>
        )}

        {/* CMS Tab (Admin) */}
        {activeTab === 'CMS' && isAdmin && (
            <div className="max-w-4xl animate-fade-in">
                <h2 className="text-2xl font-serif italic mb-6 dark:text-white">Site Content Management</h2>
                <div className="bg-white dark:bg-zinc-900 p-8 border border-gray-100 dark:border-zinc-800 space-y-6">
                    <p className="text-sm text-gray-500">Edit the landing page text and imagery directly.</p>
                    <textarea 
                        className="w-full h-96 p-4 border border-gray-200 dark:border-zinc-700 font-mono text-xs bg-transparent dark:text-white"
                        value={JSON.stringify(cmsForm, null, 2)}
                        onChange={(e) => {
                            try {
                                setCmsForm(JSON.parse(e.target.value));
                            } catch (err) {
                                // invalid json
                            }
                        }}
                    />
                    <button onClick={handleSaveCMS} className="bg-black text-white px-6 py-3 text-xs font-bold uppercase dark:bg-white dark:text-black">Publish Updates</button>
                </div>
            </div>
        )}
      </main>
    </div>
  );
};

import React, { useState } from 'react';
import { BadgeCheck, MapPin, Users, Star, ArrowLeft, Heart, Share2, Instagram, Twitter, Globe, Check, X, Link, Facebook, Mail } from 'lucide-react';
import { Vendor, Product, ViewState } from '../types';

interface VendorProfileViewProps {
  vendor: Vendor;
  onProductSelect: (product: Product) => void;
  onNavigate: (view: ViewState) => void;
  products: Product[];
  savedItems?: Product[];
  onToggleSave?: (product: Product) => void;
  onToggleFollow?: (vendor: Vendor) => Promise<void>;
  isFollowing?: boolean;
}

export const VendorProfileView: React.FC<VendorProfileViewProps> = ({ 
