  <div className="h-[50vh] flex items-center justify-center">
    <Loader className="animate-spin text-luxury-gold" size={24} />
  </div>
);

const App: React.FC = () => {
  // State
  const [currentView, setCurrentView] = useState<ViewState>('LANDING');
  const [userRole, setUserRole] = useState<UserRole>(UserRole.BUYER);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [savedItems, setSavedItems] = useState<Product[]>([]);
  const [followedVendors, setFollowedVendors] = useState<Vendor[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isSavedOpen, setIsSavedOpen] = useState(false);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [selectedVendor, setSelectedVendor] = useState<Vendor | null>(null);
  const [selectedDesignerFilter, setSelectedDesignerFilter] = useState<string | null>(null);

  // Auth Navigation State
  const [authInitialMode, setAuthInitialMode] = useState<'LOGIN' | 'REGISTER'>('LOGIN');
  const [authInitialRole, setAuthInitialRole] = useState<UserRole>(UserRole.BUYER);

  // Data State
  const [vendors, setVendors] = useState<Vendor[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [notifications, setNotifications] = useState<AppNotification[]>([]);
  const [contactSubmissions, setContactSubmissions] = useState<ContactSubmission[]>([]);
  const [cmsContent, setCmsContent] = useState<LandingPageContent | undefined>(undefined);
  // Removed blocking isLoadingData state

  // Visual Search State
  const [visualSearchResults, setVisualSearchResults] = useState<Product[] | null>(null);

  // Initialize DB and Fetch Data - Non-blocking
  const refreshData = async () => {
    try {
      // Prioritize content visible on landing
      const [dbContent, dbVendors, dbProducts] = await Promise.all([
        fetchLandingContent(),
        fetchVendors(), 
        fetchProducts(),
      ]);

      setCmsContent(dbContent);
      setVendors(dbVendors);
      setProducts(dbProducts);

      // Fetch user-specific data (Notifications, Orders, Follows)
      const currentUserId = auth.currentUser?.uid;

      // Load heavy data in parallel
      const [dbOrders, dbUsers, dbContacts, dbNotifications] = await Promise.all([
        fetchOrders(),
        fetchUsers(),
        fetchContactSubmissions(),
        fetchNotifications(currentUserId)
      ]);

      setOrders(dbOrders);
      setAllUsers(dbUsers);
      setContactSubmissions(dbContacts);
      setNotifications(dbNotifications);

      if (currentUserId) {
          const follows = await fetchUserFollowedVendors(currentUserId);
          setFollowedVendors(follows);
      }

    } catch (error) {
      console.error("Failed to refresh data", error);
    }
  };

  useEffect(() => {
    // Initial Load
    const initData = async () => {
      try {
        await seedDatabase();
        await refreshData();
      } catch (error) {
        console.error("Database initialization failed.", error);
      }
    };
    initData();

    // Load saved items from local storage
    const saved = localStorage.getItem('myfitstore_saved');
    if (saved) {
      try {
        setSavedItems(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load saved items", e);
      }
    }

    // Real-time: Poll for general data updates every 30 seconds
    const pollInterval = setInterval(() => {
        refreshData();
    }, 30000);

    return () => clearInterval(pollInterval);
  }, []);

  // Sync saved items to local storage
  useEffect(() => {
    localStorage.setItem('myfitstore_saved', JSON.stringify(savedItems));
  }, [savedItems]);

  // Handle Shared Outfit URL Params
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const outfitIds = params.get('outfit');

    // Only process if products are loaded
    if (outfitIds && products.length > 0) {
      const ids = outfitIds.split(',');
      const sharedProducts = products.filter(p => ids.includes(p.id));

      if (sharedProducts.length > 0) {
        setSavedItems(sharedProducts);
        setIsSavedOpen(true); // Open the drawer to show the shared outfit

        // Clean URL without reloading
        const newUrl = window.location.pathname;
        window.history.replaceState({}, '', newUrl);
      }
    }
  }, [products]);

  // Simulate Live Transactions (Context-Aware)
  useEffect(() => {
      const simulateLiveTraffic = setInterval(async () => {
          // Guard: Need data to simulate
          if (products.length === 0 || vendors.length === 0) return;

          const currentUser = auth.currentUser;
          const currentUserId = currentUser?.uid;
          const currentUserEmail = currentUser?.email;

          // --- 1. BUYER SCENARIO: Order Status Updates ---
          // If logged in as a buyer, randomly update their existing orders to 'Shipped' or 'Delivered'
          if (userRole === UserRole.BUYER && currentUserEmail) {
              const myOrders = orders.filter(o => o.customerName.toLowerCase() === currentUserEmail.toLowerCase() && o.status !== 'Delivered');

              if (myOrders.length > 0 && Math.random() > 0.6) {
                  const targetOrder = myOrders[Math.floor(Math.random() * myOrders.length)];
                  const nextStatus = targetOrder.status === 'Processing' ? 'Shipped' : 'Delivered';

                  await updateOrderStatusInDb(targetOrder.id, nextStatus);

                  const notif: AppNotification = {
                      id: `notif_status_${Date.now()}`,
                      userId: currentUserId || 'guest',
                      title: 'Order Update',
                      message: `Your order #${targetOrder.id.slice(-6)} has been ${nextStatus}.`,
                      read: false,
                      date: new Date().toISOString(),
                      type: 'ORDER',
                      link: 'ORDERS'
                  };
                  await createNotificationInDb(notif);
                  await refreshData();
                  return; // prioritize one event per tick
              }
          }

          // --- 2. VENDOR / ADMIN SCENARIO: New Sales ---
          let targetProduct: Product | null = null;

          if (userRole === UserRole.VENDOR && currentUserId) {
              // Find this vendor's details to pick THEIR product
              const myVendor = vendors.find(v => v.id === currentUserId || v.email === currentUserEmail);
              if (myVendor) {
                  const myProducts = products.filter(p => p.designer === myVendor.name);
                  if (myProducts.length > 0) {
                      targetProduct = myProducts[Math.floor(Math.random() * myProducts.length)];
                  }
              }
          } else if (userRole === UserRole.ADMIN) {
              // Admin sees random sales across platform
              targetProduct = products[Math.floor(Math.random() * products.length)];
          } else if (userRole === UserRole.BUYER && Math.random() > 0.8) {
              // Rare chance for Buyer to see a "Platform Activity" notification (Social Proof)
              targetProduct = products[Math.floor(Math.random() * products.length)];
          }

          // Execute Sale Simulation
          if (targetProduct && Math.random() > 0.5) {
              const vendorObj = vendors.find(v => v.name === targetProduct!.designer);
              if (!vendorObj) return;

              const mockOrder: Order = {
                  id: `ord_live_${Date.now()}`,
                  customerName: `Guest_${Math.floor(Math.random() * 9000) + 1000}`,
                  date: new Date().toISOString(),
                  total: targetProduct.price,
                  status: 'Processing',
                  items: [{
                      ...targetProduct,
                      quantity: 1,
                      size: targetProduct.sizes?.[0] || 'M',
                      stock: targetProduct.stock
                  }]
              };

              await createOrderInDb(mockOrder);

              // Notify the Vendor (Always)
              const vendorNotif: AppNotification = {
                  id: `notif_sale_${mockOrder.id}`,
                  userId: vendorObj.id,
                  title: 'New Sale',
                  message: `You sold 1x ${targetProduct.name} to ${mockOrder.customerName}.`,
                  read: false,
                  date: new Date().toISOString(),
                  type: 'ORDER',
                  link: 'FULFILLMENT'
              };
              await createNotificationInDb(vendorNotif);

              // If currently logged in as Admin, notify them too
              if (userRole === UserRole.ADMIN && currentUserId) {
                   const adminNotif: AppNotification = {
                      id: `notif_admin_${mockOrder.id}`,
                      userId: currentUserId,
                      title: 'Platform Sale',
                      message: `${vendorObj.name} sold ${targetProduct.name} ($${targetProduct.price}).`,
                      read: false,
                      date: new Date().toISOString(),
                      type: 'SYSTEM',
                      link: 'TRANSACTIONS'
                  };
                  await createNotificationInDb(adminNotif);
              }

              console.log("Simulated live order:", mockOrder.id);
              await refreshData();
          }

      }, 15000); // Check every 15s for lively feel

      return () => clearInterval(simulateLiveTraffic);
  }, [products, vendors, userRole, orders]);

  // Listen for Auth State Changes
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (user) => {
      if (user) {
        if (user.emailVerified) {
          setIsLoggedIn(true);
          // Refresh data immediately on login to get user notifications
          refreshData(); 

          // Determine Role
          const adminEmails = ['instantassetrecovery830@gmail.com', 'juliemtrice7@proton.me', 'mikelarry00764@proton.me'];
          if (adminEmails.includes(user.email?.toLowerCase() || '')) {
              setUserRole(UserRole.ADMIN);
          } else {
              // Check if user has an assigned role in the Users table
              // We might need to fetch users if not yet loaded in the background
              let currentUsers = allUsers;
              if (currentUsers.length === 0) {
                 currentUsers = await fetchUsers();
              }

              const dbUser = currentUsers.find(u => u.email.toLowerCase() === user.email?.toLowerCase());

              if (dbUser && dbUser.role) {
                  setUserRole(dbUser.role);
              } else {
                  // Fallback to Vendor check
                  let currentVendors = vendors;
                  if (currentVendors.length === 0) {
                      currentVendors = await fetchVendors();
                  }
                  const matchingVendor = currentVendors.find(v => v.email?.toLowerCase() === user.email?.toLowerCase());

                  if (matchingVendor) {
                      setUserRole(UserRole.VENDOR);
                  } else {
                      setUserRole(UserRole.BUYER);
                  }
              }
          }
        } else {
          // User exists but is not verified
          setIsLoggedIn(false);
          setUserRole(UserRole.BUYER);
          setCurrentView('AUTH');
        }
      } else {
        setIsLoggedIn(false);
        setUserRole(UserRole.BUYER);
        setNotifications([]); // Clear notifications on logout
        setFollowedVendors([]);
      }
    });

    return () => unsubscribe();
  }, [allUsers, vendors]); // Depend on data to ensure correct role assignment

  // Derived State: Active Products (only from active vendors who are verified)
  const activeProducts = products.filter(product => {
      const vendor = vendors.find(v => v.name === product.designer);
      return vendor ? (vendor.subscriptionStatus === 'ACTIVE' && vendor.verificationStatus === 'VERIFIED') : true; 
  });

  // Feature Flags Management
  const [featureFlags, setFeatureFlags] = useState<FeatureFlags>({
    enableMarketplace: true,
    enableReviews: true,
    enableAiStyleMatch: true,
    maintenanceMode: false
  });

  // Handlers
  const handleNavigate = (view: ViewState) => {
    if (view === 'AUTH') {
        // Reset defaults if navigating generically
        setAuthInitialMode('LOGIN');
        setAuthInitialRole(UserRole.BUYER);
    }

    if (view !== 'MARKETPLACE') {
        setSelectedDesignerFilter(null);
    }
    setCurrentView(view);
    window.scrollTo({ top: 0, behavior: 'auto' });
    setIsCartOpen(false);
    setIsSavedOpen(false);
  };

  const handleAuthNavigation = (mode: 'LOGIN' | 'REGISTER', role: UserRole) => {
    setAuthInitialMode(mode);
    setAuthInitialRole(role);
    setCurrentView('AUTH');
    window.scrollTo({ top: 0, behavior: 'auto' });
    setIsCartOpen(false);
    setIsSavedOpen(false);
  };

  const handleDesignerSelect = (designerName: string) => {
    const vendor = vendors.find(v => v.name === designerName);
    if (vendor) {
      setSelectedVendor(vendor);
      handleNavigate('VENDOR_PROFILE');
    } else {
      setSelectedDesignerFilter(designerName);
      handleNavigate('MARKETPLACE');
    }
  };

  const handleLogin = (role: UserRole) => {
    setUserRole(role);
    if (role === UserRole.ADMIN) {
      handleNavigate('ADMIN_PANEL');
    } else if (role === UserRole.VENDOR) {
      handleNavigate('VENDOR_DASHBOARD');
    } else if (role === UserRole.BUYER) {
      handleNavigate('BUYER_DASHBOARD');
    } else {
      handleNavigate('MARKETPLACE');
    }
  };

  const handleLogout = async () => {
    try {
      await signOut(auth);
      handleNavigate('LANDING');
    } catch (error) {
      console.error("Logout Error:", error);
    }
  };

  const handleProductSelect = (product: Product) => {
    setSelectedProduct(product);
    handleNavigate('PRODUCT_DETAIL');
  };

  const handleAddToCart = (product: Product, size: string, measurements?: string) => {
    const newItem: CartItem = {
      ...product,
      quantity: 1,
      size: size,
      measurements: measurements || ''
    };
    setCart([...cart, newItem]);
    setIsCartOpen(true);
  };

  const handleUpdateCartItem = (index: number, updates: Partial<CartItem>) => {
    const newCart = [...cart];
    newCart[index] = { ...newCart[index], ...updates };
    setCart(newCart);
  };

  const handleRemoveFromCart = (index: number) => {
    const newCart = [...cart];
    newCart.splice(index, 1);
    setCart(newCart);
  };

  // Saved Items Handler
  const handleToggleSave = (product: Product) => {
    setSavedItems(prev => {
      const exists = prev.find(p => p.id === product.id);
      if (exists) {
        return prev.filter(p => p.id !== product.id);
      } else {
        setIsSavedOpen(true); // Open drawer when saving for better feedback
        return [...prev, product];
      }
    });
  };

  // Follow Vendor Handler
  const handleToggleFollow = async (vendor: Vendor) => {
      const currentUser = auth.currentUser;
      if (!currentUser) {
          handleAuthNavigation('LOGIN', UserRole.BUYER);
          return;
      }

      const isFollowing = followedVendors.some(v => v.id === vendor.id);
      const followerId = currentUser.uid;

      if (isFollowing) {
          // Optimistic update
          setFollowedVendors(prev => prev.filter(v => v.id !== vendor.id));
          await removeFollowerFromDb(followerId, vendor.id);
      } else {
          // Optimistic update
          setFollowedVendors(prev => [...prev, vendor]);

          const newFollower: Follower & { followerId: string } = {
              id: `follow_${followerId}_${vendor.id}`,
              name: currentUser.displayName || 'Anonymous',
              avatar: currentUser.photoURL || '',
              location: 'Unknown',
              joined: new Date().toISOString(),
              purchases: 0,
              style: 'General',
              vendorId: vendor.id,
              followerId: followerId
          };
          await addFollowerToDb(newFollower);
      }
  };

  // --- VISUAL SEARCH HANDLER ---
  const handleVisualSearch = async (file: File) => {
    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = reader.result as string;

      const matchIds = await searchProductsByImage(base64, activeProducts);
      const matchedProducts = activeProducts.filter(p => matchIds.includes(p.id));

      setVisualSearchResults(matchedProducts);
      handleNavigate('MARKETPLACE');
    };
    reader.readAsDataURL(file);
  };

  const handleClearVisualSearch = () => {
    setVisualSearchResults(null);
  };

  // --- ASYNC DATA HANDLERS ---

  const handleAddProduct = async (product: Product) => {
    await addProductToDb(product);
    await refreshData();
  };

  const handleUpdateProduct = async (updatedProduct: Product) => {
    await updateProductInDb(updatedProduct);
    await refreshData();
  };

  const handleDeleteProduct = async (productId: string) => {
    await deleteProductFromDb(productId);
    await refreshData();
  };

  const handleSetVendors = async (updatedVendors: Vendor[]) => {
    for (const v of updatedVendors) {
       await updateVendorInDb(v);
    }
    await refreshData();
  };

  const handleUpdateUser = async (user: User) => {
      await updateUserInDb(user);
      await refreshData();
  };

  const handleUpdateOrderStatus = async (orderId: string, status: Order['status']) => {
    await updateOrderStatusInDb(orderId, status);
    await refreshData();
  };

  const handlePlaceOrder = async (order: Order) => {
     await createOrderInDb(order);
     await refreshData();
     setCart([]); 
  };

  const handleUpdateCMSContent = async (content: LandingPageContent) => {
    await updateLandingContentInDb(content);
    await refreshData();
  };

  const toggleFeatureFlag = (key: keyof FeatureFlags) => {
    setFeatureFlags(prev => ({ ...prev, [key]: !prev[key] }));
  };

  // View Routing
  const renderView = () => {
    if (currentView === 'AUTH') {
      return (
        <Suspense fallback={<LoadingFallback />}>
          <AuthView 
            onLogin={handleLogin} 
            onNavigate={handleNavigate} 
            cmsContent={cmsContent}
            initialMode={authInitialMode}
            initialRole={authInitialRole}
          />
        </Suspense>
      );
    }

    if (featureFlags.maintenanceMode && userRole !== UserRole.ADMIN) {
      return (
        <div className="h-screen flex items-center justify-center flex-col">
          <h1 className="text-4xl font-serif">MyFitStore</h1>
          <p className="mt-4 uppercase tracking-widest text-sm">Under Maintenance</p>
        </div>
      );
    }

    switch (currentView) {
      case 'LANDING':
        return (
          // Landing View is NOT suspended to ensure instant load
          <LandingView 
            onNavigate={handleNavigate} 
            isLoggedIn={isLoggedIn} 
            userRole={userRole} 
            vendors={vendors}
            products={activeProducts}
            onDesignerClick={handleDesignerSelect}
            cmsContent={cmsContent}
            onAuthRequest={handleAuthNavigation}
          />
        );
      case 'MARKETPLACE':
        return (
          <Suspense fallback={<LoadingFallback />}>
            <MarketplaceView 
              onNavigate={handleNavigate} 
              onProductSelect={handleProductSelect} 
              initialDesigner={selectedDesignerFilter}
              products={visualSearchResults || activeProducts}
              vendors={vendors}
              customTitle={visualSearchResults ? "Visual Search Results" : null}
              onClearFilter={handleClearVisualSearch}
              savedItems={savedItems}
              onToggleSave={handleToggleSave}
            />
          </Suspense>
        );
      case 'NEW_ARRIVALS':
        return (
          <Suspense fallback={<LoadingFallback />}>
            <NewArrivalsView 
                onProductSelect={handleProductSelect} 
                products={activeProducts}
                savedItems={savedItems}
                onToggleSave={handleToggleSave}
            />
          </Suspense>
        );
      case 'DESIGNERS':
        return (
          <Suspense fallback={<LoadingFallback />}>
            <DesignersView onSelectDesigner={handleDesignerSelect} vendors={vendors} />
          </Suspense>
        );
      case 'VENDOR_PROFILE':
        return (
          <Suspense fallback={<LoadingFallback />}>
            {selectedVendor ? (
              <VendorProfileView 
                vendor={selectedVendor} 
                onProductSelect={handleProductSelect}
                onNavigate={handleNavigate}
                products={activeProducts}
                savedItems={savedItems}
                onToggleSave={handleToggleSave}
                onToggleFollow={handleToggleFollow}
                isFollowing={followedVendors.some(v => v.id === selectedVendor.id)}
              />
            ) : <DesignersView onSelectDesigner={handleDesignerSelect} vendors={vendors} />}
          </Suspense>
        );
      case 'PRODUCT_DETAIL':
        const associatedVendor = vendors.find(v => v.name === selectedProduct?.designer);
        return (
          <Suspense fallback={<LoadingFallback />}>
            {selectedProduct ? (
              <ProductDetail 
                product={selectedProduct}
                vendor={associatedVendor}
                onAddToCart={handleAddToCart} 
                onBack={() => handleNavigate('MARKETPLACE')}
                onViewDesigner={() => associatedVendor && handleDesignerSelect(associatedVendor.name)}
                featureFlags={featureFlags}
                savedItems={savedItems}
                onToggleSave={handleToggleSave}
              />
            ) : (
                <MarketplaceView 
                    onNavigate={handleNavigate} 
                    onProductSelect={handleProductSelect} 
                    products={activeProducts}
                    vendors={vendors}
                    savedItems={savedItems}
                    onToggleSave={handleToggleSave}
                />
            )}
          </Suspense>
        );
      case 'VENDOR_DASHBOARD':
      case 'ADMIN_PANEL':
      case 'BUYER_DASHBOARD':
        return (
          <Suspense fallback={<LoadingFallback />}>
            <Dashboard 
              role={userRole} 
              featureFlags={featureFlags} 
              toggleFeatureFlag={toggleFeatureFlag}
              onNavigate={handleNavigate}
              vendors={vendors}
              setVendors={handleSetVendors}
              orders={orders}
              onUpdateOrderStatus={handleUpdateOrderStatus}
              products={products}
              users={allUsers}
              onAddProduct={handleAddProduct}
              onUpdateProduct={handleUpdateProduct}
              onDeleteProduct={handleDeleteProduct}
              onProductSelect={handleProductSelect}
              onUpdateUser={handleUpdateUser}
              cmsContent={cmsContent}
              onUpdateCMSContent={handleUpdateCMSContent}
              contactSubmissions={contactSubmissions}
              followedVendors={followedVendors}
              onToggleFollow={handleToggleFollow}
              onDesignerClick={handleDesignerSelect}
            />
          </Suspense>
        );
      case 'PROFILE_SETTINGS':
        return (
          <Suspense fallback={<LoadingFallback />}>
            <Dashboard 
              role={userRole} 
              featureFlags={featureFlags} 
              toggleFeatureFlag={toggleFeatureFlag}
              onNavigate={handleNavigate}
              initialTab="PROFILE"
              vendors={vendors}
              setVendors={handleSetVendors}
              products={products}
              users={allUsers}
              onAddProduct={handleAddProduct}
              onUpdateProduct={handleUpdateProduct}
              onDeleteProduct={handleDeleteProduct}
              onProductSelect={handleProductSelect}
              onUpdateUser={handleUpdateUser}
              cmsContent={cmsContent}
              onUpdateCMSContent={handleUpdateCMSContent}
              contactSubmissions={contactSubmissions}
              followedVendors={followedVendors}
              onToggleFollow={handleToggleFollow}
            />
          </Suspense>
        );
      case 'PRICING':
        return (
          <Suspense fallback={<LoadingFallback />}>
            <PricingView onNavigate={handleNavigate} onRegister={() => handleAuthNavigation('REGISTER', UserRole.VENDOR)} />
          </Suspense>
        );
      case 'ABOUT':
        return (
          <Suspense fallback={<LoadingFallback />}>
            <AboutView onNavigate={handleNavigate} cmsContent={cmsContent} />
          </Suspense>
        );
      default:
        return (
          <LandingView 
            onNavigate={handleNavigate} 
            isLoggedIn={isLoggedIn} 
            userRole={userRole} 
            vendors={vendors} 
            products={activeProducts} 
            onDesignerClick={handleDesignerSelect} 
            cmsContent={cmsContent} 
            onAuthRequest={handleAuthNavigation} 
          />
        );
    }
  };

  if (featureFlags.maintenanceMode && userRole !== UserRole.ADMIN) {
    return (
      <div className="min-h-screen bg-luxury-cream flex flex-col items-center justify-center animate-fade-in">
        <h1 className="text-3xl font-serif font-bold tracking-widest mb-6">MyFitStore</h1>
        <p className="mt-4 text-xs font-bold uppercase tracking-widest text-gray-400">Under Maintenance</p>
      </div>
    );
  }

  return (
    <Layout 
      role={userRole} 
      cart={cart}
      savedItems={savedItems}
      isCartOpen={isCartOpen}
      setIsCartOpen={setIsCartOpen}
      isSavedOpen={isSavedOpen}
      setIsSavedOpen={setIsSavedOpen}
      onUpdateCartItem={handleUpdateCartItem}
      onRemoveFromCart={handleRemoveFromCart}
      onToggleSave={handleToggleSave}
      onNavigate={handleNavigate}
      onRoleChange={setUserRole}
      currentView={currentView}
      isLoggedIn={isLoggedIn}
      onLogout={handleLogout}
      onPlaceOrder={handlePlaceOrder}
      onVisualSearch={handleVisualSearch}
      onAuthRequest={handleAuthNavigation}
      notifications={notifications}
      onRefreshNotifications={refreshData}
    >
      {renderView()}

      {/* AI Concierge - Rendered globally but passed active products context. Hidden on AUTH view. Lazy loaded. */}
      {currentView !== 'AUTH' && (
        <Suspense fallback={null}>
          <AiConcierge products={activeProducts} />
        </Suspense>
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid,
  PieChart, Pie, Cell
} from 'recharts';
import { 
  Package, Users, DollarSign, Activity, Settings, LayoutDashboard, Shirt, ShoppingBag, 
  Plus, Trash2, ArrowUpRight,
  Palette, FileText,
  MapPin, Mail, Globe, Instagram, Twitter, Heart, Truck, CheckCircle, AlertCircle, 
  UserX, Camera, MessageCircle, Ban, Diamond, Check, Edit2, X, ShieldCheck, BadgeCheck,
  Lock, MessageSquare, Flag, Store, Grid, ChevronDown, Loader, Star, Save, Menu, Wallet, ArrowLeft, Inbox,
  Phone, Clock, Filter, Search, Facebook
} from 'lucide-react';
import { FeatureFlags, UserRole, Product, ViewState, Vendor, Order, User, LandingPageContent, ContactSubmission, Follower } from '../types.ts';
import { updateUserPassword, auth } from '../services/firebase.ts';
import { VendorProfileView } from './VendorProfileView.tsx';

const COLORS = ['#0a0a0a', '#C5A059', '#8B8580', '#E5E5E5', '#4A0404'];

interface DashboardProps {
  role: UserRole;
  featureFlags: FeatureFlags;
  toggleFeatureFlag: (key: keyof FeatureFlags) => void;
  onNavigate: (view: ViewState) => void;
  vendors?: Vendor[];
  setVendors?: (vendors: Vendor[]) => Promise<void>;
  orders?: Order[];
  onUpdateOrderStatus?: (orderId: string, status: Order['status']) => Promise<void>;
  products?: Product[];
  users?: User[];
  onAddProduct?: (product: Product) => Promise<void>;
  onUpdateProduct?: (product: Product) => Promise<void>;
  onDeleteProduct?: (productId: string) => Promise<void>;
  onProductSelect?: (product: Product) => void;
  onUpdateUser?: (user: User) => Promise<void>;
  cmsContent?: LandingPageContent;
  onUpdateCMSContent?: (content: LandingPageContent) => Promise<void>;
  contactSubmissions?: ContactSubmission[];
  initialTab?: string;
  followedVendors?: Vendor[];
  onToggleFollow?: (vendor: Vendor) => Promise<void>;
  onDesignerClick?: (designerName: string) => void;
}

export const Dashboard: React.FC<DashboardProps> = ({
  role,
  featureFlags,
  toggleFeatureFlag,
  onNavigate,
  vendors = [],
  setVendors,
  orders = [],
  onUpdateOrderStatus,
  products = [],
  users = [],
  onAddProduct,
  onUpdateProduct,
  onDeleteProduct,
  onProductSelect,
  onUpdateUser,
  cmsContent,
  onUpdateCMSContent,
  contactSubmissions = [],
  initialTab,
  followedVendors = [],
  onToggleFollow,
  onDesignerClick
}) => {
  const [activeTab, setActiveTab] = useState(initialTab || 'OVERVIEW');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  // Profile State
  const [newPassword, setNewPassword] = useState('');
  const [passwordMsg, setPasswordMsg] = useState('');

  // Update active tab if initialTab changes
  useEffect(() => {
    if (initialTab) setActiveTab(initialTab);
  }, [initialTab]);

  const currentUser = auth.currentUser;

  // Filter Data based on Role
  const myOrders = useMemo(() => {
    if (role === UserRole.ADMIN) return orders;
    if (role === UserRole.VENDOR) {
        // Find vendor based on current user email
        const vendor = vendors.find(v => v.email === currentUser?.email);
        if (!vendor) return [];
        // Filter orders that contain items from this vendor
        return orders.filter(o => o.items.some(i => i.designer === vendor.name));
    }
    // Buyer
    return orders.filter(o => o.customerName === currentUser?.email);
  }, [orders, role, vendors, currentUser]);

  const myProducts = useMemo(() => {
    if (role === UserRole.ADMIN) return products;
    if (role === UserRole.VENDOR) {
        const vendor = vendors.find(v => v.email === currentUser?.email);
        if (!vendor) return [];
        return products.filter(p => p.designer === vendor.name);
    }
    return [];
  }, [products, role, vendors, currentUser]);

  // Calculations for Overview
  const totalRevenue = useMemo(() => {
      return myOrders.reduce((sum, order) => sum + order.total, 0);
  }, [myOrders]);

  const totalSales = myOrders.length;

  // Handlers for Profile
  const handlePasswordUpdate = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!newPassword) return;
      try {
          if (auth.currentUser) {
              await updateUserPassword(auth.currentUser as any, newPassword); // Type cast for our interface
              setPasswordMsg('Password updated successfully.');
              setNewPassword('');
          }
      } catch (err: any) {
          setPasswordMsg('Error updating password: ' + err.message);
      }
  };

  // Render Sidebar
  const renderSidebar = () => {
    const tabs = [
      { id: 'OVERVIEW', label: 'Overview', icon: LayoutDashboard, roles: [UserRole.ADMIN, UserRole.VENDOR, UserRole.BUYER] },
      { id: 'ORDERS', label: 'Orders', icon: ShoppingBag, roles: [UserRole.ADMIN, UserRole.VENDOR, UserRole.BUYER] },
      { id: 'PRODUCTS', label: 'Products', icon: Shirt, roles: [UserRole.ADMIN, UserRole.VENDOR] },
      { id: 'CUSTOMERS', label: 'Customers', icon: Users, roles: [UserRole.ADMIN] },
      { id: 'VENDORS', label: 'Vendors', icon: Store, roles: [UserRole.ADMIN] },
      { id: 'MESSAGES', label: 'Messages', icon: Inbox, roles: [UserRole.ADMIN] },
      { id: 'CMS', label: 'Content', icon: FileText, roles: [UserRole.ADMIN] },
      { id: 'FOLLOWING', label: 'Following', icon: Heart, roles: [UserRole.BUYER] },
      { id: 'PROFILE', label: 'Settings', icon: Settings, roles: [UserRole.ADMIN, UserRole.VENDOR, UserRole.BUYER] },
    ];

    return (
      <div className={`fixed left-0 top-0 h-full bg-white border-r border-gray-100 transition-all duration-300 z-40 ${isSidebarOpen ? 'w-64' : 'w-20'} pt-20 hidden md:block`}>
        <div className="flex flex-col h-full">
          <div className="flex-1 py-6 px-4 space-y-2">
            {tabs.filter(t => t.roles.includes(role)).map(tab => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id)}
                className={`w-full flex items-center gap-4 p-3 text-sm font-medium transition-colors rounded-sm ${activeTab === tab.id ? 'bg-luxury-black text-white' : 'text-gray-500 hover:bg-gray-50'}`}
              >
                <tab.icon size={20} />
                {isSidebarOpen && <span>{tab.label}</span>}
              </button>
            ))}
          </div>
          <div className="p-4 border-t border-gray-100">
             <button 
                onClick={() => setIsSidebarOpen(!isSidebarOpen)} 
                className="flex items-center gap-4 text-gray-400 hover:text-black transition-colors"
             >
                {isSidebarOpen ? <Menu size={20} /> : <ChevronDown size={20} className="rotate-90" />}
                {isSidebarOpen && <span className="text-xs uppercase tracking-widest">Collapse</span>}
             </button>
          </div>
        </div>
      </div>
    );
  };

  // Render Content
  const renderContent = () => {
    switch (activeTab) {
      case 'OVERVIEW':
        return (
          <div className="space-y-8 animate-fade-in">
             <h2 className="text-2xl font-serif italic">Dashboard Overview</h2>

             {/* Stats Cards */}
             <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div className="bg-white p-6 border border-gray-100 shadow-sm">
                   <div className="flex items-center justify-between mb-4">
                      <h3 className="text-xs font-bold uppercase tracking-widest text-gray-400">Total Revenue</h3>
                      <DollarSign className="text-luxury-gold" size={20} />
                   </div>
                   <p className="text-3xl font-serif">${totalRevenue.toLocaleString()}</p>
                </div>
                <div className="bg-white p-6 border border-gray-100 shadow-sm">
                   <div className="flex items-center justify-between mb-4">
                      <h3 className="text-xs font-bold uppercase tracking-widest text-gray-400">Total Orders</h3>
                      <ShoppingBag className="text-luxury-gold" size={20} />
                   </div>
                   <p className="text-3xl font-serif">{totalSales}</p>
                </div>
                {role !== UserRole.BUYER && (
                  <div className="bg-white p-6 border border-gray-100 shadow-sm">
                    <div className="flex items-center justify-between mb-4">
                        <h3 className="text-xs font-bold uppercase tracking-widest text-gray-400">Products</h3>
                        <Shirt className="text-luxury-gold" size={20} />
                    </div>
                    <p className="text-3xl font-serif">{myProducts.length}</p>
                  </div>
                )}
             </div>

             {/* Chart (Placeholder) */}
             <div className="bg-white p-6 border border-gray-100 shadow-sm h-80">
                <h3 className="text-xs font-bold uppercase tracking-widest text-gray-400 mb-6">Activity Overview</h3>
                <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={myOrders.slice(0, 7).map(o => ({ name: o.date, amount: o.total }))}>
                        <CartesianGrid strokeDasharray="3 3" vertical={false} />
                        <XAxis dataKey="name" tick={{fontSize: 10}} />
                        <YAxis tick={{fontSize: 10}} />
                        <Tooltip />
                        <Bar dataKey="amount" fill="#C5A059" />
                    </BarChart>
                </ResponsiveContainer>
             </div>
          </div>
        );

      case 'ORDERS':
        return (
          <div className="space-y-8 animate-fade-in">
             <h2 className="text-2xl font-serif italic">Order History</h2>
             <div className="bg-white border border-gray-100 overflow-hidden">
                <table className="w-full text-left text-sm">
                   <thead className="bg-gray-50 text-xs uppercase tracking-widest text-gray-500 font-bold">
                      <tr>
                         <th className="p-4">Order ID</th>
                         <th className="p-4">Date</th>
                         <th className="p-4">Customer</th>
                         <th className="p-4">Total</th>
                         <th className="p-4">Status</th>
                         {role !== UserRole.BUYER && <th className="p-4">Actions</th>}
                      </tr>
                   </thead>
                   <tbody className="divide-y divide-gray-100">
                      {myOrders.map(order => (
                         <tr key={order.id} className="hover:bg-gray-50/50">
                            <td className="p-4 font-medium">{order.id}</td>
                            <td className="p-4 text-gray-500">{new Date(order.date).toLocaleDateString()}</td>
                            <td className="p-4">{order.customerName}</td>
                            <td className="p-4 font-bold">${order.total}</td>
                            <td className="p-4">
                               <span className={`px-2 py-1 text-[10px] font-bold uppercase tracking-widest rounded-full ${
                                  order.status === 'Delivered' ? 'bg-green-100 text-green-700' :
                                  order.status === 'Shipped' ? 'bg-blue-100 text-blue-700' :
                                  'bg-yellow-100 text-yellow-700'
                               }`}>
                                  {order.status}
                               </span>
                            </td>
                            {role !== UserRole.BUYER && (
                               <td className="p-4">
                                  {onUpdateOrderStatus && order.status !== 'Delivered' && (
                                     <button 
                                        onClick={() => onUpdateOrderStatus(order.id, order.status === 'Processing' ? 'Shipped' : 'Delivered')}
                                        className="text-xs underline hover:text-luxury-gold"
                                     >
                                        Mark {order.status === 'Processing' ? 'Shipped' : 'Delivered'}
                                     </button>
                                  )}
                               </td>
                            )}
                         </tr>
                      ))}
                      {myOrders.length === 0 && (
                          <tr>
                              <td colSpan={6} className="p-8 text-center text-gray-400">No orders found.</td>
                          </tr>
                      )}
                   </tbody>
                </table>
             </div>
          </div>
        );

      case 'PRODUCTS':
         return (
             <div className="space-y-8 animate-fade-in">
                 <div className="flex justify-between items-center">
                     <h2 className="text-2xl font-serif italic">Product Management</h2>
                     {onAddProduct && (
                         <button className="bg-luxury-black text-white px-4 py-2 text-xs font-bold uppercase tracking-widest flex items-center gap-2 hover:bg-luxury-gold transition-colors">
                             <Plus size={16} /> Add Product
                         </button>
                     )}
                 </div>

                 <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-4 gap-6">
                     {myProducts.map(product => (
                         <div key={product.id} className="bg-white border border-gray-100 group relative">
                             <div className="aspect-[3/4] bg-gray-50 overflow-hidden">
                                 <img src={product.image} alt={product.name} className="w-full h-full object-cover" />
                             </div>
                             <div className="p-4">
                                 <h3 className="font-bold text-sm truncate">{product.name}</h3>
                                 <p className="text-xs text-gray-500 uppercase">{product.category}</p>
                                 <div className="flex justify-between items-center mt-2">
                                     <span className="text-sm font-medium">${product.price}</span>
                                     <span className="text-xs text-gray-400">{product.stock} in stock</span>
                                 </div>
                             </div>
                             <div className="absolute top-2 right-2 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                 <button className="p-2 bg-white rounded-full shadow-md hover:text-luxury-gold"><Edit2 size={14} /></button>
                                 {onDeleteProduct && (
                                     <button onClick={() => onDeleteProduct(product.id)} className="p-2 bg-white rounded-full shadow-md hover:text-red-500"><Trash2 size={14} /></button>
