                      {followedVendors.map(vendor => (
                          <div key={vendor.id} className="bg-white border border-gray-100 p-6 flex flex-col items-center text-center">
                              <img src={vendor.avatar} alt={vendor.name} className="w-20 h-20 rounded-full object-cover mb-4" />
                              <h3 className="font-bold text-lg mb-1">{vendor.name}</h3>
                              <p className="text-xs text-gray-500 mb-4 line-clamp-2">{vendor.bio}</p>
                              <div className="flex gap-2">
                                  <button 
                                    onClick={() => onDesignerClick && onDesignerClick(vendor.name)}
                                    className="bg-black text-white px-4 py-2 text-[10px] font-bold uppercase tracking-widest hover:bg-luxury-gold transition-colors"
                                  >
                                      View Profile
                                  </button>
                                  {onToggleFollow && (
                                      <button 
                                        onClick={() => onToggleFollow(vendor)}
                                        className="border border-gray-200 px-4 py-2 text-[10px] font-bold uppercase tracking-widest hover:border-black transition-colors"
                                      >
                                          Unfollow
                                      </button>
                                  )}
