          );

      case 'PROFILE':
        return (
          <div className="max-w-2xl space-y-8 animate-fade-in">
             <h2 className="text-2xl font-serif italic">Account Settings</h2>

             {/* Profile Update */}
             <div className="bg-white p-8 border border-gray-100">
                <h3 className="text-sm font-bold uppercase tracking-widest mb-6">Personal Details</h3>
                <div className="flex items-center gap-6 mb-8">
                    <div className="w-20 h-20 bg-gray-100 rounded-full overflow-hidden">
                        {auth.currentUser?.photoURL ? (
                            <img src={auth.currentUser.photoURL} alt="Profile" className="w-full h-full object-cover" />
                        ) : (
                            <UserIcon size={32} className="m-auto mt-6 text-gray-400" />
                        )}
                    </div>
                    <div>
                        <p className="font-bold text-lg">{auth.currentUser?.displayName || 'User'}</p>
                        <p className="text-gray-500 text-sm">{auth.currentUser?.email}</p>
                        <div className="mt-2 flex gap-2">
                           <span className="bg-gray-100 text-[10px] px-2 py-1 uppercase tracking-wider font-bold">{role}</span>
                           {auth.currentUser?.emailVerified && <span className="bg-green-50 text-green-700 text-[10px] px-2 py-1 uppercase tracking-wider font-bold flex items-center gap-1"><CheckCircle size={10} /> Verified</span>}
                        </div>
                    </div>
                </div>
             </div>

             {/* Security */}
             <div className="bg-white p-8 border border-gray-100">
                 <h3 className="text-sm font-bold uppercase tracking-widest mb-6">Security</h3>
                 <form onSubmit={handlePasswordUpdate} className="space-y-4">
                     <div>
                         <label className="text-xs font-bold text-gray-400 uppercase tracking-widest block mb-2">New Password</label>
                         <input 
                            type="password"
                            value={newPassword}
                            onChange={(e) => setNewPassword(e.target.value)}
                            className="w-full border-b border-gray-200 py-2 text-sm focus:border-black outline-none"
                            placeholder="••••••••"
                         />
                     </div>
                     {passwordMsg && (
                         <p className={`text-xs ${passwordMsg.includes('success') ? 'text-green-600' : 'text-red-500'}`}>{passwordMsg}</p>
                     )}
                     <button 
                        type="submit" 
                        disabled={!newPassword}
                        className="bg-black text-white px-6 py-3 text-xs font-bold uppercase tracking-widest hover:bg-luxury-gold transition-colors disabled:opacity-50"
                     >
                         Update Password
                     </button>
                 </form>
             </div>

             {/* Feature Flags (Admin Only) */}
             {role === UserRole.ADMIN && (
                 <div className="bg-white p-8 border border-gray-100">
                     <h3 className="text-sm font-bold uppercase tracking-widest mb-6">System Controls</h3>
                     <div className="space-y-4">
                         {Object.entries(featureFlags).map(([key, value]) => (
                             <div key={key} className="flex justify-between items-center">
                                 <span className="text-sm text-gray-600 capitalize">{key.replace(/([A-Z])/g, ' $1').trim()}</span>
                                 <button 
                                    onClick={() => toggleFeatureFlag(key as keyof FeatureFlags)}
                                    className={`w-12 h-6 rounded-full p-1 transition-colors ${value ? 'bg-green-500' : 'bg-gray-200'}`}
                                 >
                                     <div className={`w-4 h-4 bg-white rounded-full shadow-sm transition-transform ${value ? 'translate-x-6' : 'translate-x-0'}`} />
                                 </button>
                             </div>
                         ))}
                     </div>
                 </div>
             )}
          </div>
        );

      default:
        return <div className="p-8">Select a tab</div>;
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 pt-20">
       {renderSidebar()}
       <div className={`transition-all duration-300 ${isSidebarOpen ? 'md:ml-64' : 'md:ml-20'} p-6 md:p-12`}>
           {renderContent()}
       </div>
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Filter, ChevronDown, Heart, Camera, X } from 'lucide-react';
import { Product, ViewState, Vendor } from '../types.ts';

interface MarketplaceViewProps {
  onProductSelect: (product: Product) => void;
  onNavigate: (view: ViewState) => void;
  initialDesigner?: string | null;
  products: Product[];
  vendors: Vendor[];
  customTitle?: string | null;
  onClearFilter?: () => void;
  savedItems?: Product[];
  onToggleSave?: (product: Product) => void;
}

const FILTERS = ['All', 'Outerwear', 'Bottoms', 'Knitwear', 'Footwear', 'Accessories'];

export const MarketplaceView: React.FC<MarketplaceViewProps> = ({ 
  onProductSelect, 
  initialDesigner, 
  products,
  vendors,
  customTitle,
  onClearFilter,
  savedItems = [],
  onToggleSave
}) => {
  const [activeCategory, setActiveCategory] = useState('All');
  const [activeDesigner, setActiveDesigner] = useState('All Designers');

  // Handle initial filter from props
  useEffect(() => {
    if (initialDesigner) {
      setActiveDesigner(initialDesigner);
    } else {
        setActiveDesigner('All Designers');
    }
  }, [initialDesigner]);

  // Extract unique active designers from passed products
  const designers = useMemo(() => {
    const unique = Array.from(new Set(products.map(p => p.designer)));
    return ['All Designers', ...unique.sort()];
  }, [products]);

  const filteredProducts = products.filter(p => {
    const matchesCategory = activeCategory === 'All' || p.category === activeCategory;
    const matchesDesigner = activeDesigner === 'All Designers' || p.designer === activeDesigner;
    return matchesCategory && matchesDesigner;
  });

  const isSaved = (productId: string) => savedItems.some(p => p.id === productId);

  return (
    <div className="min-h-screen pt-4 md:pt-12 pb-24">
      {/* Header & Filters */}
      <div className="max-w-7xl mx-auto px-4 md:px-6 mb-6 md:mb-12 sticky top-[4.5rem] md:top-20 z-30 bg-white/90 backdrop-blur-md py-4 transition-all border-b border-gray-100/50">
        <div className="flex flex-col gap-4 md:gap-8">

          {/* Top Row: Title + Designer Select */}
          <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4 md:gap-6">
            <div className="flex items-center gap-4 w-full md:w-auto justify-between md:justify-start">
                <h1 className="text-2xl md:text-4xl font-serif italic truncate">
                    {customTitle || "Ready-to-Wear"}
                </h1>
                {customTitle && onClearFilter && (
                    <button 
                        onClick={onClearFilter}
                        className="bg-gray-100 hover:bg-gray-200 text-[10px] md:text-xs font-bold uppercase tracking-widest px-3 py-1.5 rounded-full flex items-center gap-1 transition-colors duration-200 active:scale-95 shrink-0"
                    >
                        <X size={12} /> Clear
                    </button>
                )}
            </div>

            {/* Designer Dropdown */}
            {!customTitle && (
            <div className="relative w-full md:w-auto md:min-w-[240px]">
              <label className="text-[10px] uppercase tracking-widest text-gray-400 mb-1 md:mb-2 block font-bold">Filter by Designer</label>
              <div className="relative group">
                <select 
                  value={activeDesigner}
                  onChange={(e) => setActiveDesigner(e.target.value)}
                  className="w-full appearance-none bg-transparent border-b border-gray-300 py-2 pr-8 text-xs md:text-sm font-bold uppercase tracking-widest focus:outline-none focus:border-black cursor-pointer hover:border-luxury-gold transition-colors duration-200"
                >
                  {designers.map(d => (
                    <option key={d} value={d}>{d}</option>
                  ))}
                </select>
                <ChevronDown size={14} className="absolute right-0 top-1/2 -translate-y-1/2 pointer-events-none text-gray-400 group-hover:text-black transition-colors" />
              </div>
            </div>
            )}
          </div>

          {/* Bottom Row: Category Pills */}
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2 overflow-x-auto w-full pb-1 scrollbar-hide -mx-4 px-4 md:mx-0 md:px-0">
              {FILTERS.map(cat => (
                <button
                  key={cat}
                  onClick={() => setActiveCategory(cat)}
                  className={`text-[10px] md:text-xs uppercase tracking-widest whitespace-nowrap px-4 py-2 border rounded-full transition-all duration-200 active:scale-95 flex-shrink-0 ${
                    activeCategory === cat 
                      ? 'bg-black text-white border-black' 
                      : 'bg-transparent text-gray-500 border-gray-200 hover:border-black hover:text-black'
                  }`}
                >
                  {cat}
                </button>
              ))}
            </div>
             <button className="hidden md:flex items-center gap-2 text-xs uppercase font-bold ml-4 border-l pl-6 border-gray-200 hover:text-luxury-gold transition-colors duration-200 whitespace-nowrap active:scale-95">
              <Filter size={14} /> More Filters
            </button>
          </div>

        </div>
      </div>

      {/* Grid */}
      <div className="max-w-7xl mx-auto px-3 md:px-6">
        {filteredProducts.length === 0 ? (
           <div className="py-24 text-center animate-fade-in">
             <div className="flex justify-center mb-4">
                {customTitle ? <Camera size={32} className="text-gray-300" /> : <Filter size={32} className="text-gray-300" />}
             </div>
             <p className="text-xl font-serif italic text-gray-400 mb-4">
                 {customTitle ? "No visual matches found in our current collection." : "No pieces found matching your criteria."}
             </p>
             <button 
               onClick={() => {
                   if (onClearFilter) onClearFilter();
                   setActiveCategory('All'); 
                   setActiveDesigner('All Designers');
               }} 
               className="text-xs font-bold uppercase border-b border-black pb-1 hover:text-luxury-gold hover:border-luxury-gold transition-colors duration-200 active:scale-95"
             >
               View Full Collection
             </button>
           </div>
        ) : (
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-x-3 gap-y-8 md:gap-x-6 md:gap-y-16 animate-fade-in">
          {filteredProducts.map((product) => (
            <div 
              key={product.id} 
              className="group cursor-pointer active:scale-[0.98] transition-transform duration-200"
              onClick={() => onProductSelect(product)}
            >
              <div className="relative aspect-[3/4] overflow-hidden bg-gray-100 mb-3 md:mb-6">
                <img 
                  src={product.image} 
                  alt={product.name} 
                  className="w-full h-full object-cover transition-transform duration-500 ease-out group-hover:scale-110"
                />

                {/* Overlay Action - Hidden on mobile to prevent sticky hover states */}
                <div className="hidden md:flex absolute inset-0 bg-black/10 transition-opacity duration-300 opacity-0 group-hover:opacity-100 items-end justify-center pb-8">
                  <button className="bg-white text-black text-xs font-bold uppercase tracking-widest px-8 py-3 hover:bg-luxury-black hover:text-white transition-all duration-200 shadow-xl transform translate-y-4 opacity-0 group-hover:translate-y-0 group-hover:opacity-100 active:scale-95">
                    Quick View
                  </button>
                </div>

                <button 
                    onClick={(e) => { e.stopPropagation(); onToggleSave && onToggleSave(product); }}
                    className={`absolute top-2 right-2 md:top-4 md:right-4 p-1.5 md:p-0 transition-transform hover:scale-110 duration-300 md:opacity-0 md:group-hover:opacity-100 ${isSaved(product.id) ? 'opacity-100 text-luxury-gold' : 'text-white mix-blend-difference'}`}
                >
                  <Heart size={18} md:size={20} strokeWidth={1.5} fill={isSaved(product.id) ? "currentColor" : "none"} />
                </button>
              </div>

              <div className="flex flex-col md:flex-row justify-between items-start gap-1">
                <div className="overflow-hidden w-full">
                  <h3 className="text-[9px] md:text-xs font-bold uppercase tracking-widest mb-0.5 md:mb-1 truncate text-gray-500 md:text-black">{product.designer}</h3>
                  <p className="font-serif text-xs md:text-base text-gray-900 md:text-gray-600 italic group-hover:text-black transition-colors duration-200 truncate">{product.name}</p>
                </div>
                <span className="text-xs md:text-sm font-medium mt-1 md:mt-0">${product.price}</span>
              </div>
            </div>
          ))}
        </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid,
  PieChart, Pie, Cell
} from 'recharts';
import { 
  Package, Users, DollarSign, Activity, Settings, LayoutDashboard, Shirt, ShoppingBag, 
  Plus, Trash2, ArrowUpRight,
  Palette, FileText,
  MapPin, Mail, Globe, Instagram, Twitter, Heart, Truck, CheckCircle, AlertCircle, 
  UserX, Camera, MessageCircle, Ban, Diamond, Check, Edit2, X, ShieldCheck, BadgeCheck,
  Lock, MessageSquare, Flag, Store, Grid, ChevronDown, Loader, Star, Save, Menu, Wallet, ArrowLeft, Inbox,
  Phone, Clock, Filter, Search, Facebook
} from 'lucide-react';
import { FeatureFlags, UserRole, Product, ViewState, Vendor, Order, User, LandingPageContent, ContactSubmission, Follower } from '../types.ts';
import { updateUserPassword, auth } from '../services/firebase.ts';
import { VendorProfileView } from './VendorProfileView.tsx';

const COLORS = ['#0a0a0a', '#C5A059', '#8B8580', '#E5E5E5', '#4A0404'];

interface DashboardProps {
  role: UserRole;
  featureFlags: FeatureFlags;
  toggleFeatureFlag: (key: keyof FeatureFlags) => void;
  onNavigate: (view: ViewState) => void;
  vendors?: Vendor[];
  setVendors?: (vendors: Vendor[]) => Promise<void>;
  orders?: Order[];
  onUpdateOrderStatus?: (orderId: string, status: Order['status']) => Promise<void>;
  products?: Product[];
  users?: User[];
  onAddProduct?: (product: Product) => Promise<void>;
  onUpdateProduct?: (product: Product) => Promise<void>;
  onDeleteProduct?: (productId: string) => Promise<void>;
  onProductSelect?: (product: Product) => void;
  onUpdateUser?: (user: User) => Promise<void>;
  cmsContent?: LandingPageContent;
  onUpdateCMSContent?: (content: LandingPageContent) => Promise<void>;
  contactSubmissions?: ContactSubmission[];
  initialTab?: string;
  followedVendors?: Vendor[];
  onToggleFollow?: (vendor: Vendor) => Promise<void>;
  onDesignerClick?: (designerName: string) => void;
}

export const Dashboard: React.FC<DashboardProps> = ({
  role,
  featureFlags,
  toggleFeatureFlag,
  onNavigate,
  vendors = [],
  setVendors,
  orders = [],
  onUpdateOrderStatus,
  products = [],
  users = [],
  onAddProduct,
  onUpdateProduct,
  onDeleteProduct,
  onProductSelect,
  onUpdateUser,
  cmsContent,
  onUpdateCMSContent,
  contactSubmissions = [],
  initialTab,
  followedVendors = [],
  onToggleFollow,
  onDesignerClick
}) => {
  const [activeTab, setActiveTab] = useState(initialTab || 'OVERVIEW');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false); // Default closed on mobile, logic handled in render

  // Profile State
  const [newPassword, setNewPassword] = useState('');
  const [passwordMsg, setPasswordMsg] = useState('');

  // Update active tab if initialTab changes
  useEffect(() => {
    if (initialTab) setActiveTab(initialTab);
  }, [initialTab]);

  // Force sidebar open on desktop mount
  useEffect(() => {
      const handleResize = () => {
          if (window.innerWidth >= 768) {
              setIsSidebarOpen(true);
          } else {
              setIsSidebarOpen(false);
          }
      };
      handleResize(); // Initial check
      window.addEventListener('resize', handleResize);
      return () => window.removeEventListener('resize', handleResize);
  }, []);

  const currentUser = auth.currentUser;

  // Filter Data based on Role
  const myOrders = useMemo(() => {
    if (role === UserRole.ADMIN) return orders;
    if (role === UserRole.VENDOR) {
        // Find vendor based on current user email
        const vendor = vendors.find(v => v.email === currentUser?.email);
        if (!vendor) return [];
        // Filter orders that contain items from this vendor
        return orders.filter(o => o.items.some(i => i.designer === vendor.name));
    }
    // Buyer
    return orders.filter(o => o.customerName === currentUser?.email);
  }, [orders, role, vendors, currentUser]);

  const myProducts = useMemo(() => {
    if (role === UserRole.ADMIN) return products;
    if (role === UserRole.VENDOR) {
        const vendor = vendors.find(v => v.email === currentUser?.email);
        if (!vendor) return [];
        return products.filter(p => p.designer === vendor.name);
    }
    return [];
  }, [products, role, vendors, currentUser]);

  // Calculations for Overview
  const totalRevenue = useMemo(() => {
      return myOrders.reduce((sum, order) => sum + order.total, 0);
  }, [myOrders]);

  const totalSales = myOrders.length;

  // Handlers for Profile
  const handlePasswordUpdate = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!newPassword) return;
      try {
          if (auth.currentUser) {
              await updateUserPassword(auth.currentUser as any, newPassword); // Type cast for our interface
              setPasswordMsg('Password updated successfully.');
              setNewPassword('');
          }
      } catch (err: any) {
          setPasswordMsg('Error updating password: ' + err.message);
      }
  };

  // Render Sidebar
  const renderSidebar = () => {
    const tabs = [
      { id: 'OVERVIEW', label: 'Overview', icon: LayoutDashboard, roles: [UserRole.ADMIN, UserRole.VENDOR, UserRole.BUYER] },
      { id: 'ORDERS', label: 'Orders', icon: ShoppingBag, roles: [UserRole.ADMIN, UserRole.VENDOR, UserRole.BUYER] },
      { id: 'PRODUCTS', label: 'Products', icon: Shirt, roles: [UserRole.ADMIN, UserRole.VENDOR] },
      { id: 'CUSTOMERS', label: 'Customers', icon: Users, roles: [UserRole.ADMIN] },
      { id: 'VENDORS', label: 'Vendors', icon: Store, roles: [UserRole.ADMIN] },
      { id: 'MESSAGES', label: 'Messages', icon: Inbox, roles: [UserRole.ADMIN] },
      { id: 'CMS', label: 'Content', icon: FileText, roles: [UserRole.ADMIN] },
      { id: 'FOLLOWING', label: 'Following', icon: Heart, roles: [UserRole.BUYER] },
      { id: 'PROFILE', label: 'Settings', icon: Settings, roles: [UserRole.ADMIN, UserRole.VENDOR, UserRole.BUYER] },
    ];

    return (
      <>
        {/* Mobile Backdrop */}
        <div 
            className={`fixed inset-0 bg-black/60 backdrop-blur-sm z-40 md:hidden transition-opacity duration-300 ${isSidebarOpen ? 'opacity-100 visible' : 'opacity-0 invisible'}`}
            onClick={() => setIsSidebarOpen(false)}
        />

        {/* Sidebar Panel */}
        <div className={`fixed left-0 top-0 h-full bg-white border-r border-gray-100 transition-transform duration-300 ease-in-out z-50 w-64 pt-6 md:pt-20 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'} md:translate-x-0 flex flex-col`}>
            {/* Mobile Header in Sidebar */}
            <div className="md:hidden px-6 pb-6 flex justify-between items-center border-b border-gray-50">
                <h2 className="text-xl font-serif italic">Dashboard</h2>
                <button onClick={() => setIsSidebarOpen(false)} className="p-2 hover:bg-gray-100 rounded-full">
                    <X size={20} />
                </button>
            </div>

            <div className="flex-1 py-6 px-4 space-y-2 overflow-y-auto">
                {tabs.filter(t => t.roles.includes(role)).map(tab => (
                <button
                    key={tab.id}
                    onClick={() => { setActiveTab(tab.id); setIsSidebarOpen(false); }}
                    className={`w-full flex items-center gap-4 p-3 text-sm font-medium transition-colors rounded-sm ${activeTab === tab.id ? 'bg-luxury-black text-white' : 'text-gray-500 hover:bg-gray-50'}`}
                >
                    <tab.icon size={20} />
                    <span>{tab.label}</span>
                </button>
                ))}
            </div>

            <div className="p-4 border-t border-gray-100 hidden md:block">
                <button 
                    onClick={() => setIsSidebarOpen(!isSidebarOpen)} // On desktop this might just collapse to icons (logic simplified here)
                    className="flex items-center gap-4 text-gray-400 hover:text-black transition-colors"
                >
                    <span className="text-xs uppercase tracking-widest w-full text-center">MyFitStore</span>
                </button>
            </div>
        </div>
      </>
    );
  };

  // Render Content
  const renderContent = () => {
    switch (activeTab) {
      case 'OVERVIEW':
        return (
          <div className="space-y-8 animate-fade-in pb-20 md:pb-0">
             <div className="flex items-center justify-between">
                 <h2 className="text-2xl font-serif italic">Dashboard Overview</h2>
                 {/* Mobile Menu Trigger */}
                 <button onClick={() => setIsSidebarOpen(true)} className="md:hidden p-2 border border-gray-200 rounded-sm">
                     <Menu size={20} />
                 </button>
             </div>

             {/* Stats Cards */}
             <div className="grid grid-cols-1 md:grid-cols-3 gap-4 md:gap-6">
                <div className="bg-white p-6 border border-gray-100 shadow-sm rounded-sm">
                   <div className="flex items-center justify-between mb-4">
                      <h3 className="text-xs font-bold uppercase tracking-widest text-gray-400">Total Revenue</h3>
                      <DollarSign className="text-luxury-gold" size={20} />
                   </div>
                   <p className="text-3xl font-serif">${totalRevenue.toLocaleString()}</p>
                </div>
                <div className="bg-white p-6 border border-gray-100 shadow-sm rounded-sm">
                   <div className="flex items-center justify-between mb-4">
                      <h3 className="text-xs font-bold uppercase tracking-widest text-gray-400">Total Orders</h3>
                      <ShoppingBag className="text-luxury-gold" size={20} />
                   </div>
                   <p className="text-3xl font-serif">{totalSales}</p>
                </div>
                {role !== UserRole.BUYER && (
                  <div className="bg-white p-6 border border-gray-100 shadow-sm rounded-sm">
                    <div className="flex items-center justify-between mb-4">
                        <h3 className="text-xs font-bold uppercase tracking-widest text-gray-400">Products</h3>
                        <Shirt className="text-luxury-gold" size={20} />
                    </div>
                    <p className="text-3xl font-serif">{myProducts.length}</p>
                  </div>
                )}
             </div>

             {/* Chart (Placeholder) */}
             <div className="bg-white p-6 border border-gray-100 shadow-sm h-80 rounded-sm">
                <h3 className="text-xs font-bold uppercase tracking-widest text-gray-400 mb-6">Activity Overview</h3>
                <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={myOrders.slice(0, 7).map(o => ({ name: o.date, amount: o.total }))}>
                        <CartesianGrid strokeDasharray="3 3" vertical={false} />
                        <XAxis dataKey="name" tick={{fontSize: 10}} />
                        <YAxis tick={{fontSize: 10}} />
