                                  <th className="p-4">Joined</th>
                                  <th className="p-4">Spent</th>
                                  <th className="p-4">Status</th>
                                  <th className="p-4">Actions</th>
                              </tr>
                          </thead>
                          <tbody className="divide-y divide-gray-100">
                              {users?.filter(u => u.role === UserRole.BUYER).map(user => (
                                  <tr key={user.id} className="hover:bg-gray-50/50">
                                      <td className="p-4 flex items-center gap-3">
                                          <img src={user.avatar || 'https://via.placeholder.com/32'} className="w-8 h-8 rounded-full object-cover" alt="" />
                                          <span className="font-medium">{user.name}</span>
                                      </td>
                                      <td className="p-4">{user.email}</td>
                                      <td className="p-4 text-gray-500">{new Date(user.joined).toLocaleDateString()}</td>
                                      <td className="p-4 font-mono">{user.spend || '$0.00'}</td>
                                      <td className="p-4">
                                          <span className={`px-2 py-1 text-[10px] font-bold uppercase tracking-widest rounded-full ${user.status === 'ACTIVE' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                                              {user.status}
