                                      </td>
                                      <td className="p-4">
                                          {onUpdateUser && (
                                              <button 
                                                  onClick={() => onUpdateUser({ ...user, status: user.status === 'ACTIVE' ? 'SUSPENDED' : 'ACTIVE' })}
