                                      </td>
                                  </tr>
                              ))}
                          </tbody>
                      </table>
                  </div>
              </div>
          );

      case 'VENDORS':
          return (
              <div className="space-y-8 animate-fade-in pb-20 md:pb-0">
                  <div className="flex items-center justify-between">
                      <h2 className="text-2xl font-serif italic">Atelier Management</h2>
                      <button onClick={() => setIsSidebarOpen(true)} className="md:hidden p-2 border border-gray-200 rounded-sm">
                          <Menu size={20} />
                      </button>
                  </div>

                  <div className="bg-white border border-gray-100 overflow-x-auto rounded-sm">
                      <table className="w-full text-left text-sm min-w-[800px]">
                          <thead className="bg-gray-50 text-xs uppercase tracking-widest text-gray-500 font-bold">
                              <tr>
                                  <th className="p-4">Brand</th>
                                  <th className="p-4">Email</th>
                                  <th className="p-4">Plan</th>
                                  <th className="p-4">Verification</th>
                                  <th className="p-4">Subscription</th>
                                  <th className="p-4">Actions</th>
                              </tr>
                          </thead>
                          <tbody className="divide-y divide-gray-100">
                              {vendors.map(vendor => (
                                  <tr key={vendor.id} className="hover:bg-gray-50/50">
                                      <td className="p-4 flex items-center gap-3">
                                          <img src={vendor.avatar} className="w-8 h-8 rounded-full object-cover border border-gray-200" alt="" />
                                          <div>
                                              <p className="font-bold text-xs uppercase">{vendor.name}</p>
                                              <p className="text-[10px] text-gray-400">{vendor.location || 'Unknown'}</p>
